import React, { useEffect, useRef } from 'react';

const Background: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let particles: Particle[] = [];
    const particleCount = 60;

    class Particle {
      x: number;
      y: number;
      vx: number;
      vy: number;
      size: number;
      opacity: number;

      constructor(w: number, h: number) {
        this.x = Math.random() * w;
        this.y = Math.random() * h;
        this.vx = (Math.random() - 0.5) * 0.4;
        this.vy = (Math.random() - 0.5) * 0.4;
        this.size = Math.random() * 2 + 1;
        this.opacity = Math.random() * 0.5 + 0.1;
      }

      update(w: number, h: number) {
        this.x += this.vx;
        this.y += this.vy;

        if (this.x < 0 || this.x > w) this.vx *= -1;
        if (this.y < 0 || this.y > h) this.vy *= -1;
      }

      draw(ctx: CanvasRenderingContext2D) {
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(100, 150, 255, ${this.opacity})`;
        ctx.fill();
      }
    }

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      init();
    };

    const init = () => {
      particles = [];
      for (let i = 0; i < particleCount; i++) {
        particles.push(new Particle(canvas.width, canvas.height));
      }
    };

    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Draw faint connections
      ctx.lineWidth = 0.5;
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < 150) {
            ctx.beginPath();
            ctx.moveTo(particles[i].x, particles[i].y);
            ctx.lineTo(particles[j].x, particles[j].y);
            ctx.strokeStyle = `rgba(100, 150, 255, ${0.1 * (1 - dist / 150)})`;
            ctx.stroke();
          }
        }
      }

      particles.forEach(p => {
        p.update(canvas.width, canvas.height);
        p.draw(ctx);
      });
      animationFrameId = requestAnimationFrame(animate);
    };

    window.addEventListener('resize', resize);
    resize();
    animate();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className="fixed inset-0 pointer-events-none z-0"
      style={{ opacity: 0.6 }}
    />
  );
};

export default Background;

import React, { ReactNode } from 'react';
import { motion } from 'framer-motion';

interface AnimatedSectionProps {
  children: ReactNode;
  className?: string;
  delay?: number;
}

const AnimatedSection: React.FC<AnimatedSectionProps> = ({ children, className = '', delay = 0 }) => {
  return (
    <motion.section
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-100px" }}
      transition={{ 
        duration: 1.2, 
        delay, 
        ease: [0.22, 1, 0.36, 1] 
      }}
      className={className}
    >
      {children}
    </motion.section>
  );
};

export default AnimatedSection;

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Menu, X } from 'lucide-react';

const Header: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'About the Center', path: '/about' },
    { name: 'Services', path: '/services' },
    { name: 'Guidelines', path: '/guidelines' },
    { name: 'Who We Are', path: '/who-we-are' },
  ];

  return (
    <header 
      className={`absolute top-0 left-0 right-0 z-50 transition-all duration-700 ease-in-out px-6 py-4 md:px-12 md:py-8 ${
        scrolled ? 'bg-black/40 backdrop-blur-md translate-y-2 mx-4 rounded-2xl border border-white/10 shadow-2xl sticky' : 'bg-transparent'
      }`}
      style={{ position: scrolled ? 'fixed' : 'absolute' }}
    >
      <div className="max-w-7xl mx-auto flex justify-between items-center">
        <Link to="/" className="flex items-center gap-2 group">
          <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform">
            <span className="text-white font-bold text-xl">D</span>
          </div>
          <span className="text-xl font-bold tracking-tight text-white group-hover:text-blue-400 transition-colors">DTC PORTAL</span>
        </Link>

        {/* Desktop Nav */}
        <nav className="hidden md:flex items-center space-x-8">
          {navLinks.map((link) => (
            <Link
              key={link.path}
              to={link.path}
              className={`text-sm font-medium tracking-wide transition-all duration-300 relative group ${
                location.pathname === link.path ? 'text-blue-400' : 'text-slate-300 hover:text-white'
              }`}
            >
              {link.name}
              <span className={`absolute -bottom-1 left-0 h-0.5 bg-blue-500 transition-all duration-300 ${
                location.pathname === link.path ? 'w-full' : 'w-0 group-hover:w-full'
              }`} />
            </Link>
          ))}
        </nav>

        {/* Mobile menu toggle */}
        <button 
          className="md:hidden text-white"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Nav */}
      <motion.nav 
        initial={false}
        animate={isMobileMenuOpen ? { height: 'auto', opacity: 1 } : { height: 0, opacity: 0 }}
        className="md:hidden overflow-hidden bg-black/90 backdrop-blur-xl mt-4 rounded-xl"
      >
        <div className="flex flex-col p-4 space-y-4">
          {navLinks.map((link) => (
            <Link
              key={link.path}
              to={link.path}
              onClick={() => setIsMobileMenuOpen(false)}
              className={`text-lg py-2 ${location.pathname === link.path ? 'text-blue-400 font-bold' : 'text-slate-300'}`}
            >
              {link.name}
            </Link>
          ))}
        </div>
      </motion.nav>
    </header>
  );
};

export default Header;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { CheckCircle2, Mail, FileText, Send, User, IdCard, Download, Printer } from 'lucide-react';
import AnimatedSection from '../components/AnimatedSection';

type ServiceType = 'FIRST_TIME' | 'RETAKE' | null;

const Services: React.FC = () => {
  const [selectedService, setSelectedService] = useState<ServiceType>(null);
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    fullName: '',
    nationalId: '',
    email: '',
    verificationCode: ''
  });
  const [isVerifying, setIsVerifying] = useState(false);
  const [isVerified, setIsVerified] = useState(false);
  const [error, setError] = useState('');

  const handleSendCode = () => {
    if (!formData.email.includes('@')) {
      setError('Please enter a valid email address');
      return;
    }
    setError('');
    setIsVerifying(true);
    // Simulate API call
    setTimeout(() => {
      setIsVerifying(false);
      alert('Verification code sent to ' + formData.email + ' (Mock Code: 1234)');
    }, 1500);
  };

  const handleVerifyCode = () => {
    if (formData.verificationCode === '1234') {
      setIsVerified(true);
      setError('');
      if (selectedService === 'RETAKE') setStep(3); // Directly to finalize for simple form
    } else {
      setError('Invalid verification code. Please try again.');
    }
  };

  const handlePrint = () => {
    window.print();
  };

  const reset = () => {
    setSelectedService(null);
    setStep(1);
    setIsVerified(false);
    setFormData({ fullName: '', nationalId: '', email: '', verificationCode: '' });
  };

  return (
    <div className="relative pt-40 pb-20 px-6">
      <div className="max-w-7xl mx-auto">
        {!selectedService ? (
          <>
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-center mb-16"
            >
              <h1 className="text-5xl md:text-7xl font-bold text-white mb-6">Our Services</h1>
              <p className="text-slate-400 text-xl max-w-2xl mx-auto">Select a path to continue your digital transformation journey.</p>
            </motion.div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-20">
              <ServiceCard 
                title="Apply for the First Time"
                description="Begin your digital transformation course registration. Complete evaluation and training for the first time."
                icon={<FileText className="text-blue-400" size={32} />}
                onClick={() => setSelectedService('FIRST_TIME')}
              />
              <ServiceCard 
                title="Retake Courses"
                description="Already registered but need to retake or re-apply? Use this simplified form to restart your process."
                icon={<CheckCircle2 className="text-emerald-400" size={32} />}
                onClick={() => setSelectedService('RETAKE')}
              />
            </div>

            <AnimatedSection className="text-center py-20 bg-slate-900/40 rounded-[40px] border border-white/5">
              <h3 className="text-2xl font-bold text-white mb-8">System Overview Video</h3>
              <div className="max-w-3xl mx-auto aspect-video bg-black rounded-3xl overflow-hidden shadow-2xl relative group cursor-pointer">
                <img src="https://picsum.photos/seed/servideo/800/450" className="w-full h-full object-cover opacity-30" alt="Video" />
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-16 h-16 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center border border-white/20">
                    <div className="w-0 h-0 border-t-[8px] border-t-transparent border-l-[14px] border-l-white border-b-[8px] border-b-transparent ml-1" />
                  </div>
                </div>
              </div>
            </AnimatedSection>
          </>
        ) : (
          <div className="max-w-3xl mx-auto">
            <button 
              onClick={reset}
              className="mb-8 text-slate-400 hover:text-white flex items-center gap-2 transition-colors"
            >
              ← Back to Services
            </button>

            <div className="bg-slate-900/60 backdrop-blur-xl border border-white/10 rounded-[32px] overflow-hidden shadow-2xl no-print">
              <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-8">
                <h2 className="text-2xl font-bold text-white">
                  {selectedService === 'FIRST_TIME' ? 'New Application Registration' : 'Course Retake Application'}
                </h2>
                <div className="flex gap-2 mt-4">
                  {[1, 2, 3].map((s) => (
                    <div key={s} className={`h-1.5 flex-1 rounded-full ${s <= step ? 'bg-white' : 'bg-white/20'}`} />
                  ))}
                </div>
              </div>

              <div className="p-8 md:p-12">
                <AnimatePresence mode="wait">
                  {step === 1 && (
                    <motion.div
                      key="step1"
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: -20 }}
                      className="space-y-6"
                    >
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <InputGroup 
                          label="Full Name" 
                          icon={<User size={18} />}
                          value={formData.fullName}
                          onChange={(e) => setFormData({...formData, fullName: e.target.value})}
                        />
                        <InputGroup 
                          label="National ID" 
                          icon={<IdCard size={18} />}
                          value={formData.nationalId}
                          onChange={(e) => setFormData({...formData, nationalId: e.target.value})}
                        />
                      </div>
                      <InputGroup 
                        label="Email Address" 
                        type="email"
                        icon={<Mail size={18} />}
                        value={formData.email}
                        onChange={(e) => setFormData({...formData, email: e.target.value})}
                      />
                      <button 
                        disabled={!formData.fullName || !formData.nationalId || !formData.email}
                        onClick={() => setStep(2)}
                        className="w-full py-4 bg-white text-slate-900 rounded-2xl font-bold hover:bg-blue-50 transition-colors disabled:opacity-50"
                      >
                        Continue to Verification
                      </button>
                    </motion.div>
                  )}

                  {step === 2 && (
                    <motion.div
                      key="step2"
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: -20 }}
                      className="space-y-8 text-center"
                    >
                      <div className="flex justify-center">
                        <div className="w-20 h-20 rounded-full bg-blue-500/10 flex items-center justify-center">
                          <Send className="text-blue-500" size={32} />
                        </div>
                      </div>
                      <div>
                        <h3 className="text-xl font-bold text-white mb-2">Verify your Email</h3>
                        <p className="text-slate-400">We need to confirm <b>{formData.email}</b> is yours.</p>
                      </div>

                      {!isVerified ? (
                        <div className="space-y-4">
                          <button 
                            onClick={handleSendCode}
                            disabled={isVerifying}
                            className="text-blue-400 font-medium hover:underline disabled:opacity-50"
                          >
                            {isVerifying ? 'Sending...' : 'Send Verification Code'}
                          </button>

                          <div className="max-w-xs mx-auto">
                             <input 
                              type="text" 
                              placeholder="Enter 4-digit code" 
                              className="w-full bg-slate-800 border border-white/10 rounded-xl px-4 py-3 text-center text-white tracking-[1em] font-mono focus:outline-none focus:border-blue-500"
                              value={formData.verificationCode}
                              onChange={(e) => setFormData({...formData, verificationCode: e.target.value})}
                              maxLength={4}
                            />
                            {error && <p className="text-red-400 text-sm mt-2">{error}</p>}
                          </div>

                          <button 
                            onClick={handleVerifyCode}
                            className="w-full py-4 bg-white text-slate-900 rounded-2xl font-bold hover:bg-blue-50 transition-colors"
                          >
                            Verify & Proceed
                          </button>
                        </div>
                      ) : (
                        <div className="space-y-6">
                          <div className="flex items-center justify-center gap-2 text-emerald-400 font-bold">
                            <CheckCircle2 size={24} /> Email Verified Successfully
                          </div>
                          <button 
                            onClick={() => setStep(3)}
                            className="w-full py-4 bg-white text-slate-900 rounded-2xl font-bold hover:bg-blue-50 transition-colors"
                          >
                            Next: Finalize Application
                          </button>
                        </div>
                      )}
                    </motion.div>
                  )}

                  {step === 3 && (
                    <motion.div
                      key="step3"
                      initial={{ opacity: 0, scale: 0.95 }}
                      animate={{ opacity: 1, scale: 1 }}
                      className="text-center space-y-8"
                    >
                      <div className="flex justify-center">
                        <div className="w-20 h-20 rounded-full bg-emerald-500/10 flex items-center justify-center">
                          <CheckCircle2 className="text-emerald-500" size={40} />
                        </div>
                      </div>
                      <div>
                        <h3 className="text-2xl font-bold text-white mb-2">Application Ready!</h3>
                        <p className="text-slate-400">Your information has been validated. Please print your official registration form below.</p>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                         <button 
                          onClick={handlePrint}
                          className="flex items-center justify-center gap-2 py-4 bg-slate-800 text-white rounded-2xl font-bold hover:bg-slate-700 transition-colors border border-white/5"
                        >
                          <Printer size={20} /> Print Form
                        </button>
                        <button 
                          onClick={handlePrint}
                          className="flex items-center justify-center gap-2 py-4 bg-blue-600 text-white rounded-2xl font-bold hover:bg-blue-500 transition-colors shadow-lg shadow-blue-500/20"
                        >
                          <Download size={20} /> Export PDF
                        </button>
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </div>

            {/* Print Only Version */}
            <div className="print-only bg-white text-black p-12 max-w-4xl mx-auto border border-black min-h-[1000px]">
               <div className="flex justify-between items-start border-b-2 border-black pb-8 mb-8">
                  <div>
                    <h1 className="text-2xl font-bold">DIGITAL TRANSFORMATION CENTER</h1>
                    <p className="text-sm font-medium">OFFICIAL REGISTRATION FORM</p>
                  </div>
                  <div className="text-right">
                    <p className="text-xs">Form ID: DTC-{Date.now().toString().slice(-8)}</p>
                    <p className="text-xs">Date: {new Date().toLocaleDateString()}</p>
                  </div>
               </div>

               <div className="space-y-12">
                  <section>
                    <h2 className="text-lg font-bold bg-gray-100 p-2 mb-4">PERSONAL INFORMATION</h2>
                    <div className="grid grid-cols-2 gap-x-12 gap-y-6">
                      <div>
                        <p className="text-xs text-gray-500 uppercase">Full Name</p>
                        <p className="border-b border-gray-300 py-1 font-semibold">{formData.fullName || '_________________________'}</p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-500 uppercase">National ID</p>
                        <p className="border-b border-gray-300 py-1 font-semibold">{formData.nationalId || '_________________________'}</p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-500 uppercase">Email Address</p>
                        <p className="border-b border-gray-300 py-1 font-semibold">{formData.email || '_________________________'}</p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-500 uppercase">Service Type</p>
                        <p className="border-b border-gray-300 py-1 font-semibold">{selectedService === 'FIRST_TIME' ? 'First Time Application' : 'Course Retake'}</p>
                      </div>
                    </div>
                  </section>

                  <section>
                    <h2 className="text-lg font-bold bg-gray-100 p-2 mb-4">VERIFICATION STATUS</h2>
                    <div className="flex items-center gap-4">
                      <div className="w-6 h-6 border-2 border-black flex items-center justify-center font-bold">✓</div>
                      <p>Identity and Email Address Authenticated via DTC Secure Portal</p>
                    </div>
                  </section>

                  <section className="pt-20">
                    <div className="grid grid-cols-2 gap-20">
                      <div className="text-center">
                        <div className="h-0.5 bg-black mb-2" />
                        <p className="text-sm">Applicant Signature</p>
                      </div>
                      <div className="text-center">
                        <div className="h-0.5 bg-black mb-2" />
                        <p className="text-sm">Registrar Stamp</p>
                      </div>
                    </div>
                  </section>
               </div>

               <div className="absolute bottom-12 left-12 right-12 text-center text-[10px] text-gray-400">
                This document is electronically generated and verified. Any alterations void the validity of the registration.
               </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

