import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { CheckCircle2, Mail, FileText, Send, User, IdCard, Download, Printer, ArrowRight, ArrowLeft } from 'lucide-react';
import AnimatedSection from '../components/AnimatedSection';
import { useLanguage } from '../LanguageContext';

type ServiceType = 'FIRST_TIME' | 'RETAKE' | null;

const Services: React.FC = () => {
  const { t, language } = useLanguage();
  const [selectedService, setSelectedService] = useState<ServiceType>(null);
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    fullName: '',
    nationalId: '',
    email: '',
    verificationCode: ''
  });
  const [isVerifying, setIsVerifying] = useState(false);
  const [isVerified, setIsVerified] = useState(false);
  const [error, setError] = useState('');

  const handleSendCode = () => {
    if (!formData.email.includes('@')) {
      setError(language === 'ar' ? 'يرجى إدخال بريد إلكتروني صالح' : 'Please enter a valid email address');
      return;
    }
    setError('');
    setIsVerifying(true);
    setTimeout(() => {
      setIsVerifying(false);
      alert((language === 'ar' ? 'تم إرسال الكود إلى ' : 'Verification code sent to ') + formData.email + ' (Mock Code: 1234)');
    }, 1500);
  };

  const handleVerifyCode = () => {
    if (formData.verificationCode === '1234') {
      setIsVerified(true);
      setError('');
      if (selectedService === 'RETAKE') setStep(3);
    } else {
      setError(language === 'ar' ? 'كود غير صالح' : 'Invalid verification code. Please try again.');
    }
  };

  const handlePrint = () => {
    window.print();
  };

  const reset = () => {
    setSelectedService(null);
    setStep(1);
    setIsVerified(false);
    setFormData({ fullName: '', nationalId: '', email: '', verificationCode: '' });
  };

  return (
    <div className="relative pt-40 pb-20 px-6">
      <div className="max-w-7xl mx-auto">
        {!selectedService ? (
          <>
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-center mb-16"
            >
              <h1 className="text-5xl md:text-7xl font-bold text-white mb-6">{t('services.title')}</h1>
              <p className="text-[#81D4FA] text-xl max-w-2xl mx-auto">{t('services.sub')}</p>
            </motion.div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-20">
              <ServiceCard 
                title={t('services.card1Title')}
                description={t('services.card1Desc')}
                icon={<FileText className="text-[#81D4FA]" size={32} />}
                onClick={() => setSelectedService('FIRST_TIME')}
                arrow={language === 'ar' ? <ArrowLeft size={18} /> : <ArrowRight size={18} />}
              />
              <ServiceCard 
                title={t('services.card2Title')}
                description={t('services.card2Desc')}
                icon={<CheckCircle2 className="text-[#00B8D4]" size={32} />}
                onClick={() => setSelectedService('RETAKE')}
                arrow={language === 'ar' ? <ArrowLeft size={18} /> : <ArrowRight size={18} />}
              />
            </div>

            <AnimatedSection className="text-center py-20 bg-[#001D6E]/30 rounded-[40px] border border-[#BBE9FF]/5">
              <h3 className="text-2xl font-bold text-white mb-8">System Overview Video</h3>
              <div className="max-w-3xl mx-auto aspect-video bg-[#001133] rounded-3xl overflow-hidden shadow-2xl relative group cursor-pointer border border-[#BBE9FF]/10">
                <img src="https://picsum.photos/seed/servideo/800/450" className="w-full h-full object-cover opacity-30" alt="Video" />
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-16 h-16 rounded-full bg-[#BBE9FF]/10 backdrop-blur-md flex items-center justify-center border border-[#BBE9FF]/20">
                    <div className={`w-0 h-0 border-t-[8px] border-t-transparent ${language === 'ar' ? 'border-r-[14px] border-r-[#BBE9FF] mr-1' : 'border-l-[14px] border-l-[#BBE9FF] ml-1'} border-b-[8px] border-b-transparent`} />
                  </div>
                </div>
              </div>
            </AnimatedSection>
          </>
        ) : (
          <div className="max-w-3xl mx-auto">
            <button 
              onClick={reset}
              className="mb-8 text-[#81D4FA] hover:text-white flex items-center gap-2 transition-colors"
            >
              {language === 'ar' ? '→' : '←'} {t('services.back')}
            </button>

            <div className="bg-[#001D6E]/60 backdrop-blur-xl border border-[#BBE9FF]/10 rounded-[32px] overflow-hidden shadow-2xl no-print">
              <div className="bg-gradient-to-r from-[#002D9C] to-[#001D6E] p-8">
                <h2 className="text-2xl font-bold text-white">
                  {selectedService === 'FIRST_TIME' ? t('services.formNew') : t('services.formRetake')}
                </h2>
                <div className="flex gap-2 mt-4">
                  {[1, 2, 3].map((s) => (
                    <div key={s} className={`h-1.5 flex-1 rounded-full ${s <= step ? 'bg-[#BBE9FF]' : 'bg-[#BBE9FF]/20'}`} />
                  ))}
                </div>
              </div>

              <div className="p-8 md:p-12">
                <AnimatePresence mode="wait">
                  {step === 1 && (
                    <motion.div
                      key="step1"
                      initial={{ opacity: 0, x: language === 'ar' ? -20 : 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: language === 'ar' ? 20 : -20 }}
                      className="space-y-6"
                    >
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <InputGroup 
                          label={t('services.fullName')}
                          icon={<User size={18} />}
                          value={formData.fullName}
                          onChange={(e) => setFormData({...formData, fullName: e.target.value})}
                          language={language}
                        />
                        <InputGroup 
                          label={t('services.nationalId')}
                          icon={<IdCard size={18} />}
                          value={formData.nationalId}
                          onChange={(e) => setFormData({...formData, nationalId: e.target.value})}
                          language={language}
                        />
                      </div>
                      <InputGroup 
                        label={t('services.email')}
                        type="email"
                        icon={<Mail size={18} />}
                        value={formData.email}
                        onChange={(e) => setFormData({...formData, email: e.target.value})}
                        language={language}
                      />
                      <button 
                        disabled={!formData.fullName || !formData.nationalId || !formData.email}
                        onClick={() => setStep(2)}
                        className="w-full py-4 bg-[#BBE9FF] text-[#001133] rounded-2xl font-bold hover:bg-white transition-colors disabled:opacity-50"
                      >
                        {t('services.continue')}
                      </button>
                    </motion.div>
                  )}

                  {step === 2 && (
                    <motion.div
                      key="step2"
                      initial={{ opacity: 0, x: language === 'ar' ? -20 : 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: language === 'ar' ? 20 : -20 }}
                      className="space-y-8 text-center"
                    >
                      <div className="flex justify-center">
                        <div className="w-20 h-20 rounded-full bg-[#0091EA]/10 flex items-center justify-center">
                          <Send className="text-[#0091EA]" size={32} />
                        </div>
                      </div>
                      <div>
                        <h3 className="text-xl font-bold text-white mb-2">{t('services.verifyTitle')}</h3>
                        <p className="text-[#81D4FA]">{t('services.verifySub')} <b className="text-[#BBE9FF]">{formData.email}</b></p>
                      </div>

                      {!isVerified ? (
                        <div className="space-y-4">
                          <button 
                            onClick={handleSendCode}
                            disabled={isVerifying}
                            className="text-[#81D4FA] font-medium hover:text-[#BBE9FF] transition-colors disabled:opacity-50"
                          >
                            {isVerifying ? t('services.sending') : t('services.sendCode')}
                          </button>

                          <div className="max-w-xs mx-auto">
                             <input 
                              type="text" 
                              placeholder="1234" 
                              className="w-full bg-[#001133] border border-[#BBE9FF]/10 rounded-xl px-4 py-3 text-center text-[#BBE9FF] tracking-[1em] font-mono focus:outline-none focus:border-[#00B8D4]"
                              value={formData.verificationCode}
                              onChange={(e) => setFormData({...formData, verificationCode: e.target.value})}
                              maxLength={4}
                            />
                            {error && <p className="text-[#00B8D4] text-sm mt-2 font-semibold">{error}</p>}
                          </div>

                          <button 
                            onClick={handleVerifyCode}
                            className="w-full py-4 bg-[#BBE9FF] text-[#001133] rounded-2xl font-bold hover:bg-white transition-colors"
                          >
                            {t('services.verifyBtn')}
                          </button>
                        </div>
                      ) : (
                        <div className="space-y-6">
                          <div className="flex items-center justify-center gap-2 text-[#00B8D4] font-bold">
                            <CheckCircle2 size={24} /> {t('services.successMsg')}
                          </div>
                          <button 
                            onClick={() => setStep(3)}
                            className="w-full py-4 bg-[#BBE9FF] text-[#001133] rounded-2xl font-bold hover:bg-white transition-colors"
                          >
                            {t('services.finalizeBtn')}
                          </button>
                        </div>
                      )}
                    </motion.div>
                  )}

                  {step === 3 && (
                    <motion.div
                      key="step3"
                      initial={{ opacity: 0, scale: 0.95 }}
                      animate={{ opacity: 1, scale: 1 }}
                      className="text-center space-y-8"
                    >
                      <div className="flex justify-center">
                        <div className="w-20 h-20 rounded-full bg-[#00B8D4]/10 flex items-center justify-center">
                          <CheckCircle2 className="text-[#00B8D4]" size={40} />
                        </div>
                      </div>
                      <div>
                        <h3 className="text-2xl font-bold text-white mb-2">{t('services.readyTitle')}</h3>
                        <p className="text-[#81D4FA]">{t('services.readySub')}</p>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                         <button 
                          onClick={handlePrint}
                          className="flex items-center justify-center gap-2 py-4 bg-[#002D9C] text-white rounded-2xl font-bold hover:bg-[#0043CE] transition-colors border border-[#BBE9FF]/10"
                        >
                          <Printer size={20} /> {t('services.printBtn')}
                        </button>
                        <button 
                          onClick={handlePrint}
                          className="flex items-center justify-center gap-2 py-4 bg-[#0091EA] text-white rounded-2xl font-bold hover:bg-[#81D4FA] hover:text-[#001133] transition-colors shadow-lg shadow-[#0091EA]/20"
                        >
                          <Download size={20} /> {t('services.exportBtn')}
                        </button>
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </div>

            <div className="print-only bg-white text-[#001133] p-12 max-w-4xl mx-auto border border-[#001133] min-h-[1000px]">
               <div className="flex justify-between items-start border-b-2 border-[#001133] pb-8 mb-8">
                  <div>
                    <h1 className="text-2xl font-bold">DIGITAL TRANSFORMATION CENTER</h1>
                    <p className="text-sm font-medium uppercase">OFFICIAL REGISTRATION FORM</p>
                  </div>
                  <div className="text-right">
                    <p className="text-xs">Form ID: DTC-{Date.now().toString().slice(-8)}</p>
                    <p className="text-xs">Date: {new Date().toLocaleDateString()}</p>
                  </div>
               </div>

               <div className="space-y-12">
                  <section>
                    <h2 className="text-lg font-bold bg-[#BBE9FF]/20 p-2 mb-4">PERSONAL INFORMATION</h2>
                    <div className="grid grid-cols-2 gap-x-12 gap-y-6">
                      <div>
                        <p className="text-xs text-[#002D9C] uppercase font-bold">Full Name</p>
                        <p className="border-b border-[#002D9C]/30 py-1 font-semibold">{formData.fullName || '_________________________'}</p>
                      </div>
                      <div>
                        <p className="text-xs text-[#002D9C] uppercase font-bold">National ID</p>
                        <p className="border-b border-[#002D9C]/30 py-1 font-semibold">{formData.nationalId || '_________________________'}</p>
                      </div>
                      <div>
                        <p className="text-xs text-[#002D9C] uppercase font-bold">Email Address</p>
                        <p className="border-b border-[#002D9C]/30 py-1 font-semibold">{formData.email || '_________________________'}</p>
                      </div>
                      <div>
                        <p className="text-xs text-[#002D9C] uppercase font-bold">Service Type</p>
                        <p className="border-b border-[#002D9C]/30 py-1 font-semibold">{selectedService === 'FIRST_TIME' ? 'First Time Application' : 'Course Retake'}</p>
                      </div>
                    </div>
                  </section>

                  <section>
                    <h2 className="text-lg font-bold bg-[#BBE9FF]/20 p-2 mb-4">VERIFICATION STATUS</h2>
                    <div className="flex items-center gap-4">
                      <div className="w-6 h-6 border-2 border-[#001133] flex items-center justify-center font-bold">✓</div>
                      <p className="font-medium text-[#001133]">Identity and Email Address Authenticated via DTC Secure Portal</p>
                    </div>
                  </section>

                  <section className="pt-20">
                    <div className="grid grid-cols-2 gap-20">
                      <div className="text-center">
                        <div className="h-0.5 bg-[#001133] mb-2" />
                        <p className="text-sm font-bold">Applicant Signature</p>
                      </div>
                      <div className="text-center">
                        <div className="h-0.5 bg-[#001133] mb-2" />
                        <p className="text-sm font-bold">Registrar Stamp</p>
                      </div>
                    </div>
                  </section>
               </div>

               <div className="absolute bottom-12 left-12 right-12 text-center text-[10px] text-[#002D9C]">
                This document is electronically generated and verified. Any alterations void the validity of the registration.
               </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

