import React, { useEffect, useRef } from 'react';
import { useTheme } from '../ThemeContext';

const Background: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const { theme } = useTheme();

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let particles: Particle[] = [];
    const particleCount = 60;

    // Palette shades adjusted for contrast
    const lightPalette = [
      'rgba(0, 45, 156, ',  // Royal Blue
      'rgba(41, 98, 255, ',  // Cobalt Blue
      'rgba(0, 145, 234, ',  // Cerulean
      'rgba(0, 67, 206, ',  // Sapphire Blue
    ];

    const darkPalette = [
      'rgba(225, 245, 254, ', // Sky Blue
      'rgba(129, 212, 250, ', // Baby Blue
      'rgba(0, 184, 212, ',   // Turquoise
      'rgba(0, 145, 234, ',   // Cerulean
    ];

    const currentPalette = theme === 'dark' ? darkPalette : lightPalette;

    class Particle {
      x: number;
      y: number;
      vx: number;
      vy: number;
      size: number;
      opacity: number;
      colorBase: string;

      constructor(w: number, h: number) {
        this.x = Math.random() * w;
        this.y = Math.random() * h;
        this.vx = (Math.random() - 0.5) * 0.25;
        this.vy = (Math.random() - 0.5) * 0.25;
        this.size = Math.random() * 3 + 1;
        this.opacity = theme === 'dark' ? Math.random() * 0.1 + 0.05 : Math.random() * 0.15 + 0.05;
        this.colorBase = currentPalette[Math.floor(Math.random() * currentPalette.length)];
      }

      update(w: number, h: number) {
        this.x += this.vx;
        this.y += this.vy;

        if (this.x < 0 || this.x > w) this.vx *= -1;
        if (this.y < 0 || this.y > h) this.vy *= -1;
      }

      draw(ctx: CanvasRenderingContext2D) {
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fillStyle = `${this.colorBase}${this.opacity})`;
        ctx.fill();
      }
    }

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      init();
    };

    const init = () => {
      particles = [];
      for (let i = 0; i < particleCount; i++) {
        particles.push(new Particle(canvas.width, canvas.height));
      }
    };

    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      ctx.lineWidth = 0.4;
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < 200) {
            ctx.beginPath();
            ctx.moveTo(particles[i].x, particles[i].y);
            ctx.lineTo(particles[j].x, particles[j].y);
            const lineOpacity = theme === 'dark' ? 0.05 : 0.08;
            ctx.strokeStyle = `rgba(0, 45, 156, ${lineOpacity * (1 - dist / 200)})`;
            ctx.stroke();
          }
        }
      }

      particles.forEach(p => {
        p.update(canvas.width, canvas.height);
        p.draw(ctx);
      });
      animationFrameId = requestAnimationFrame(animate);
    };

    window.addEventListener('resize', resize);
    resize();
    animate();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, [theme]);

  return (
    <canvas
      ref={canvasRef}
      className="fixed inset-0 pointer-events-none z-0 transition-opacity duration-1000"
      style={{ opacity: 0.5 }}
    />
  );
};

export default Background;

