                    <div className={`w-0 h-0 border-t-[8px] border-t-transparent ${language === 'ar' ? 'border-r-[14px] border-r-white mr-1' : 'border-l-[14px] border-l-white ml-1'} border-b-[8px] border-b-transparent`} />
                  </div>
                </div>
              </div>
            </AnimatedSection>
          </>
        ) : (
          <div className="max-w-3xl mx-auto">
            <button 
              onClick={reset}
              className={`mb-8 font-bold hover:underline flex items-center gap-2 transition-colors ${
                theme === 'dark' ? 'text-[#BBE9FF]' : 'text-[#002D9C]'
              }`}
            >
              {language === 'ar' ? '→' : '←'} {t('services.back')}
            </button>

            <div className={`rounded-[32px] overflow-hidden no-print border ${formContainerBg}`}>
              <div className="bg-gradient-to-r from-[#002D9C] to-[#0043CE] p-8">
                <h2 className="text-2xl font-bold text-white">
                  {selectedService === 'FIRST_TIME' ? t('services.formNew') : t('services.formRetake')}
                </h2>
                <div className="flex gap-2 mt-4">
                  {[1, 2, 3].map((s) => (
                    <div key={s} className={`h-1.5 flex-1 rounded-full ${s <= step ? 'bg-white' : 'bg-white/20'}`} />
                  ))}
                </div>
              </div>

              <div className="p-8 md:p-12">
                <AnimatePresence mode="wait">
                  {step === 1 && (
                    <motion.div
                      key="step1"
                      initial={{ opacity: 0, x: language === 'ar' ? -20 : 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: language === 'ar' ? 20 : -20 }}
                      className="space-y-6"
                    >
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <InputGroup 
                          label={t('services.fullName')}
                          icon={<User size={18} />}
                          value={formData.fullName}
                          onChange={(e) => setFormData({...formData, fullName: e.target.value})}
                          language={language}
                          theme={theme}
                        />
                        <InputGroup 
                          label={t('services.nationalId')}
                          icon={<IdCard size={18} />}
                          value={formData.nationalId}
                          onChange={(e) => setFormData({...formData, nationalId: e.target.value})}
                          language={language}
                          theme={theme}
                        />
                      </div>
                      <InputGroup 
                        label={t('services.email')}
                        type="email"
                        icon={<Mail size={18} />}
                        value={formData.email}
                        onChange={(e) => setFormData({...formData, email: e.target.value})}
                        language={language}
                        theme={theme}
                      />
                      <button 
                        disabled={!formData.fullName || !formData.nationalId || !formData.email}
                        onClick={() => setStep(2)}
                        className={`w-full py-4 rounded-2xl font-bold transition-all disabled:opacity-50 ${
                          theme === 'dark' ? 'bg-[#002D9C] text-white hover:bg-[#0043CE]' : 'bg-[#002D9C] text-white hover:bg-[#001D6E]'
                        }`}
                      >
                        {t('services.continue')}
                      </button>
                    </motion.div>
                  )}

                  {step === 2 && (
                    <motion.div
                      key="step2"
                      initial={{ opacity: 0, x: language === 'ar' ? -20 : 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: language === 'ar' ? 20 : -20 }}
                      className="space-y-8 text-center"
                    >
                      <div className="flex justify-center">
                        <div className={`w-20 h-20 rounded-full flex items-center justify-center ${
                          theme === 'dark' ? 'bg-[#0091EA]/10' : 'bg-[#0091EA]/10'
                        }`}>
                          <Send className="text-[#0091EA]" size={32} />
                        </div>
                      </div>
                      <div>
                        <h3 className={`text-xl font-bold mb-2 ${titleColor}`}>{t('services.verifyTitle')}</h3>
                        <p className={subTextColor}>{t('services.verifySub')} <b className={theme === 'dark' ? 'text-white' : 'text-[#002D9C]'}>{formData.email}</b></p>
                      </div>

                      {!isVerified ? (
                        <div className="space-y-4">
                          <button 
                            onClick={handleSendCode}
                            disabled={isVerifying}
                            className={`font-bold hover:underline disabled:opacity-50 ${
                              theme === 'dark' ? 'text-[#BBE9FF]' : 'text-[#002D9C]'
                            }`}
                          >
                            {isVerifying ? t('services.sending') : t('services.sendCode')}
                          </button>

                          <div className="max-w-xs mx-auto">
                             <input 
                              type="text" 
                              placeholder="1234" 
                              className={`w-full border-2 rounded-xl px-4 py-3 text-center tracking-[1em] font-mono focus:outline-none transition-all ${
                                theme === 'dark' 
                                  ? 'bg-white/5 border-white/10 text-white focus:border-[#BBE9FF]' 
                                  : 'bg-[#E1F5FE]/30 border-[#002D9C]/20 text-[#001133] focus:border-[#002D9C]'
                              }`}
                              value={formData.verificationCode}
                              onChange={(e) => setFormData({...formData, verificationCode: e.target.value})}
                              maxLength={4}
                            />
                            {error && <p className="text-red-500 text-sm mt-2 font-bold">{error}</p>}
                          </div>

                          <button 
                            onClick={handleVerifyCode}
                            className={`w-full py-4 rounded-2xl font-bold transition-all ${
                              theme === 'dark' ? 'bg-[#002D9C] text-white' : 'bg-[#002D9C] text-white'
                            }`}
                          >
                            {t('services.verifyBtn')}
                          </button>
                        </div>
                      ) : (
                        <div className="space-y-6">
                          <div className="flex items-center justify-center gap-2 text-[#0091EA] font-bold">
                            <CheckCircle2 size={24} /> {t('services.successMsg')}
                          </div>
                          <button 
                            onClick={() => setStep(3)}
                            className="w-full py-4 bg-[#002D9C] text-white rounded-2xl font-bold transition-all"
                          >
                            {t('services.finalizeBtn')}
                          </button>
                        </div>
                      )}
                    </motion.div>
                  )}

                  {step === 3 && (
                    <motion.div
                      key="step3"
                      initial={{ opacity: 0, scale: 0.95 }}
                      animate={{ opacity: 1, scale: 1 }}
                      className="text-center space-y-8"
                    >
                      <div className="flex justify-center">
                        <div className="w-20 h-20 rounded-full bg-[#0091EA]/10 flex items-center justify-center">
                          <CheckCircle2 className="text-[#0091EA]" size={40} />
                        </div>
                      </div>
                      <div>
                        <h3 className={`text-2xl font-bold mb-2 ${titleColor}`}>{t('services.readyTitle')}</h3>
                        <p className={subTextColor}>{t('services.readySub')}</p>
                      </div>

                      <div className="grid grid-cols-2 gap-4">
                         <button 
                          onClick={handlePrint}
                          className={`flex items-center justify-center gap-2 py-4 rounded-2xl font-bold transition-colors ${
                            theme === 'dark' ? 'bg-[#001D6E] text-white border-white/5' : 'bg-[#001133] text-white'
                          }`}
                        >
                          <Printer size={20} /> {t('services.printBtn')}
                        </button>
                        <button 
                          onClick={handlePrint}
                          className="flex items-center justify-center gap-2 py-4 bg-[#002D9C] text-white rounded-2xl font-bold transition-all shadow-lg"
                        >
                          <Download size={20} /> {t('services.exportBtn')}
                        </button>
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

