// New Selection Card Component
interface SelectionCardProps {
  title: string;
  description: string;
  buttonText: string;
  icon: React.ReactNode;
  onClick: () => void;
  theme: string;
  accent: 'primary' | 'secondary';
}

const SelectionCard: React.FC<SelectionCardProps> = ({ title, description, buttonText, icon, onClick, theme, accent }) => {
  const cardBg = theme === 'dark' ? 'bg-[#001D6E]/40 border-white/10' : 'bg-white border-[#002D9C]/10';
  const accentColor = accent === 'primary' ? 'bg-[#002D9C]' : 'bg-[#0091EA]';

  return (
    <motion.div
      whileHover={{ y: -10, boxShadow: '0 20px 40px -10px rgba(0,0,0,0.1)' }}
      className={`p-10 rounded-[32px] border flex flex-col items-center text-center transition-all ${cardBg}`}
    >
      <div className={`w-20 h-20 rounded-2xl flex items-center justify-center mb-8 bg-white shadow-lg border border-gray-100`}>
        {icon}
      </div>
      <h3 className={`text-2xl font-black mb-4 ${theme === 'dark' ? 'text-white' : 'text-[#001133]'}`}>{title}</h3>
      <p className={`text-sm mb-10 font-medium leading-relaxed ${theme === 'dark' ? 'text-white/60' : 'text-[#001133]/60'}`}>
        {description}
      </p>
      <button
        onClick={onClick}
        className={`mt-auto w-full py-4 rounded-xl text-white font-bold transition-all hover:scale-105 active:scale-95 shadow-lg ${accentColor}`}
      >
        {buttonText}
      </button>
    </motion.div>
  );
};

