const InputGroup: React.FC<{ label: string, type?: string, placeholder: string, value: string, error?: string, onChange: (val: string) => void, theme: string, dir?: 'ltr' | 'rtl' }> = ({ label, type = "text", placeholder, value, error, onChange, theme, dir }) => (
  <div className="space-y-2">
    <label className={`text-xs font-black uppercase tracking-widest ${theme === 'dark' ? 'text-[#BBE9FF]/70' : 'text-[#001133]/60'}`}>
      {label}
    </label>
    <input
      type={type}
      dir={dir}
      value={value}
      onChange={(e) => onChange(e.target.value)}
      placeholder={placeholder}
      className={`w-full border-2 rounded-xl py-4 px-5 transition-all font-medium ${
        error ? 'border-red-500 bg-red-50/5' : (theme === 'dark' ? 'bg-white/5 border-white/10 text-white focus:border-[#BBE9FF]' : 'bg-[#F0F9FF] border-[#002D9C]/10 text-[#001133] focus:border-[#002D9C]')
      }`}
    />
  </div>
);

const RadioOption: React.FC<{ id: string, name: string, label: string, checked: boolean, onChange: () => void, theme: string }> = ({ id, name, label, checked, onChange, theme }) => (
  <label htmlFor={id} className="flex items-center gap-3 group cursor-pointer">
    <div className="relative flex items-center justify-center">
      <input type="radio" id={id} name={name} checked={checked} onChange={onChange} className="peer sr-only" />
      <div className={`w-5 h-5 rounded-full border-2 transition-all peer-checked:border-[#002D9C] peer-checked:bg-[#002D9C] ${theme === 'dark' ? 'bg-white/5 border-white/10' : 'bg-[#F0F9FF] border-[#002D9C]/10'}`} />
      <div className="absolute w-2 h-2 bg-white rounded-full opacity-0 peer-checked:opacity-100 transition-opacity" />
    </div>
    <span className={`text-sm font-bold transition-colors group-hover:text-[#002D9C] ${theme === 'dark' ? 'text-white/80' : 'text-[#001133]/80'}`}>
      {label}
    </span>
  </label>
);

