const CourseCircle: React.FC<{ label: string, checked: boolean }> = ({ label, checked }) => (
  <span className={`px-2 py-0.5 ${checked ? 'border-2 border-black rounded-full shadow-[0_0_0_1px_white]' : ''}`}>
    {label}
  </span>
);

const InputGroup: React.FC<{ label: string, type?: string, placeholder: string, value: string, error?: string, onChange: (val: string) => void, theme: string, dir?: 'ltr' | 'rtl' }> = ({ label, type = "text", placeholder, value, error, onChange, theme, dir }) => (
  <div className="space-y-2">
    <label className={`text-xs font-black uppercase tracking-widest ${theme === 'dark' ? 'text-[#BBE9FF]/70' : 'text-[#001133]/60'}`}>
      {label}
    </label>
    <input
      type={type}
      dir={dir}
      value={value}
      onChange={(e) => onChange(e.target.value)}
      placeholder={placeholder}
      className={`w-full border-2 rounded-xl py-4 px-5 transition-all font-medium ${
        error ? 'border-red-500 bg-red-50/5' : (theme === 'dark' ? 'bg-white/5 border-white/10 text-white focus:border-[#BBE9FF]' : 'bg-[#F0F9FF] border-[#002D9C]/10 text-[#001133] focus:border-[#002D9C]')
      }`}
    />
    {error && <p className="text-red-500 text-xs font-bold flex items-center gap-1"><AlertCircle size={12}/> {error}</p>}
