);

const RadioOption: React.FC<{ id: string, name: string, label: string, checked: boolean, onChange: () => void, theme: string }> = ({ id, name, label, checked, onChange, theme }) => (
  <label htmlFor={id} className="flex items-center gap-3 group cursor-pointer">
    <div className="relative flex items-center justify-center">
      <input type="radio" id={id} name={name} checked={checked} onChange={onChange} className="peer sr-only" />
      <div className={`w-5 h-5 rounded-full border-2 transition-all peer-checked:border-[#002D9C] peer-checked:bg-[#002D9C] ${theme === 'dark' ? 'bg-white/5 border-white/10' : 'bg-[#F0F9FF] border-[#002D9C]/10'}`} />
