    </div>
    <span className={`text-sm font-bold transition-colors group-hover:text-[#002D9C] ${theme === 'dark' ? 'text-white/80' : 'text-[#001133]/80'}`}>
      {label}
    </span>
  </label>
);

const SelectCard: React.FC<{ id: string, label: string, checked: boolean, onChange: () => void, theme: string }> = ({ id, label, checked, onChange, theme }) => (
