      {label}
    </div>
  </label>
);

const SelectionCard: React.FC<{ title: string; description: string; buttonText: string; icon: React.ReactNode; onClick: () => void; theme: string; accent: 'primary' | 'secondary' }> = ({ title, description, buttonText, icon, onClick, theme, accent }) => {
  const cardBg = theme === 'dark' ? 'bg-[#001D6E]/40 border-white/10' : 'bg-white border-[#002D9C]/10';
  const accentColor = accent === 'primary' ? 'bg-[#002D9C]' : 'bg-[#0091EA]';

  return (
    <motion.div
      whileHover={{ y: -10, boxShadow: '0 20px 40px -10px rgba(0,0,0,0.1)' }}
