  optionalCourses: string[];
};

type ViewMode = 'selection' | 'registration' | 'reapply';

const Services: React.FC = () => {
  const { t, language } = useLanguage();
  const { theme } = useTheme();
  const [view, setView] = useState<ViewMode>('selection');
  const [step, setStep] = useState(1);
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Verification State
  const [isEmailVerified, setIsEmailVerified] = useState(false);
  const [isOtpSent, setIsOtpSent] = useState(false);
  const [otpCode, setOtpCode] = useState('');
  const [isVerifying, setIsVerifying] = useState(false);
  const [isSendingOtp, setIsSendingOtp] = useState(false);

  const [formData, setFormData] = useState<RegistrationData>({
    nameAr: '',
    nameEn: '',
    nationalId: Array(14).fill(''),
    email: '',
    whatsapp: '',
    faculty: '',
    applicantStatus: '',
    registrationType: '',
    optionalCourses: [],
  });

  const titleColor = theme === 'dark' ? 'text-white' : 'text-[#001133]';
  const subTextColor = theme === 'dark' ? 'text-[#BBE9FF]/80' : 'text-[#001133]/60';
  const cardBg = theme === 'dark' ? 'bg-[#001D6E]/80 border-white/5 shadow-2xl' : 'bg-white border-[#002D9C]/10 shadow-xl';

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.nameAr.trim()) newErrors.nameAr = "Required";
    if (!formData.nameEn.trim()) newErrors.nameEn = "Required";
    if (formData.nationalId.some(d => d === '')) newErrors.nationalId = "Complete ID required";
    if (!formData.email.trim() || !formData.email.includes('@')) newErrors.email = "Valid email required";
    if (!formData.whatsapp.trim()) newErrors.whatsapp = "Required";
    if (!formData.faculty.trim()) newErrors.faculty = "Required";
    if (!formData.applicantStatus) newErrors.applicantStatus = "Please select status";
    if (!formData.registrationType) newErrors.registrationType = "Please select registration type";
    if (formData.optionalCourses.length !== 2) newErrors.optionalCourses = "Please select exactly 2 courses";
    if (!isEmailVerified) newErrors.email = "Email verification required";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (validate()) {
      setStep(2);
      window.scrollTo(0, 0);
    }
  };

  const handleBackToStep1 = () => {
    setStep(1);
    window.scrollTo(0, 0);
  };

  const handleBackToSelection = () => {
    setView('selection');
    setStep(1);
    window.scrollTo(0, 0);
  };

  const updateNationalId = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newId = [...formData.nationalId];
    newId[index] = value.slice(-1);
    setFormData({ ...formData, nationalId: newId });

    if (value && index < 13) {
      const nextInput = document.getElementById(`id-box-${index + 1}`);
      nextInput?.focus();
    }
  };

  const toggleOptionalCourse = (course: string) => {
    setFormData(prev => {
      if (prev.optionalCourses.includes(course)) {
        return { ...prev, optionalCourses: prev.optionalCourses.filter(c => c !== course) };
      }
      if (prev.optionalCourses.length < 2) {
        return { ...prev, optionalCourses: [...prev.optionalCourses, course] };
      }
      return prev;
    });
  };

  // OTP Logic
  async function sendEmailOTP() {
    if (!formData.email || !formData.email.includes('@')) {
      setErrors({ ...errors, email: "Valid email required to send code" });
      return;
    }

    setIsSendingOtp(true);
    try {
      const { error } = await supabase.auth.signInWithOtp({
        email: formData.email,
        options: {
          shouldCreateUser: true // Changed to true to allow new applicant registration
        }
      });
      if (error) throw error;
      setIsOtpSent(true);
      setErrors(prev => ({ ...prev, email: "" }));
    } catch (err: any) {
      setErrors({ ...errors, email: err.message });
    } finally {
      setIsSendingOtp(false);
    }
  }

  async function verifyEmailOTP() {
    if (!otpCode || otpCode.length < 6) {
      setErrors({ ...errors, otp: "Valid 6-digit code required" });
      return;
    }

    setIsVerifying(true);
    try {
      const { data, error } = await supabase.auth.verifyOtp({
        email: formData.email,
        token: otpCode,
        type: 'email'
      });
      if (error) throw error;
      if (data) {
        setIsEmailVerified(true);
        setIsOtpSent(false);
        setErrors(prev => ({ ...prev, email: "" }));
      }
    } catch (err: any) {
      setErrors({ ...errors, otp: err.message });
    } finally {
      setIsVerifying(false);
    }
  }

  return (
    <div className="relative pt-40 pb-20 px-4 md:px-6 min-h-screen">
      <div className="max-w-5xl mx-auto">

        <AnimatePresence mode="wait">
          {view === 'selection' ? (
            <motion.div
              key="selection"
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="text-center"
            >
              <h1 className={`text-5xl md:text-6xl font-extrabold ${titleColor} mb-4 tracking-tight`}>
                {t('services.initialTitle')}
              </h1>
              <p className={`${subTextColor} text-lg max-w-2xl mx-auto mb-16 font-medium`}>
                {t('services.initialSub')}
              </p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl mx-auto">
                <SelectionCard
                  title={t('services.opt1Title')}
                  description={t('services.opt1Desc')}
                  buttonText={t('services.opt1Btn')}
                  icon={<UserPlus size={32} className="text-[#002D9C]" />}
                  onClick={() => setView('registration')}
                  theme={theme}
                  accent="primary"
                />
                <SelectionCard
                  title={t('services.opt2Title')}
                  description={t('services.opt2Desc')}
                  buttonText={t('services.opt2Btn')}
                  icon={<RefreshCcw size={32} className="text-[#0091EA]" />}
                  onClick={() => setView('reapply')}
                  theme={theme}
                  accent="secondary"
                />
              </div>
            </motion.div>
          ) : view === 'reapply' ? (
            <motion.div
              key="reapply"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              className={`rounded-2xl border p-12 ${cardBg}`}
            >
              <button onClick={handleBackToSelection} className="flex items-center gap-2 text-sm font-bold text-[#002D9C] mb-8 hover:underline">
                <ArrowLeft size={16} /> {t('services.back')}
              </button>
              <div className="text-center max-w-2xl mx-auto">
                <h2 className={`text-4xl font-black ${titleColor} mb-4`}>{t('services.reapplyTitle')}</h2>
                <p className={`${subTextColor} mb-12`}>{t('services.reapplySub')}</p>
                <div className="space-y-6 text-left rtl:text-right">
                  <InputGroup
                    label={t('services.nationalId')}
                    placeholder="2990101XXXXXXXXX"
                    value=""
                    onChange={() => {}}
                    theme={theme}
                  />
                  <button className="w-full py-5 bg-[#002D9C] text-white rounded-xl font-bold text-lg hover:bg-[#001D6E] transition-all">
                    {t('services.opt2Btn')}
                  </button>
                </div>
              </div>
            </motion.div>
          ) : (
            <div key="registration-flow">
              {/* Step Indicator - Hidden on Print */}
              <div className="flex justify-center mb-12 no-print items-center gap-4">
                <button onClick={handleBackToSelection} className="mr-4 p-2 rounded-full hover:bg-gray-100 transition-colors" title="Back to Selection">
                  <ArrowLeft size={24} className="text-[#002D9C]" />
                </button>
                <div className={`flex items-center justify-center w-10 h-10 rounded-full font-bold transition-all ${step === 1 ? 'bg-[#002D9C] text-white scale-110' : 'bg-[#002D9C]/20 text-[#002D9C]'}`}>1</div>
                <div className={`h-1 w-16 rounded-full transition-all ${step === 2 ? 'bg-[#002D9C]' : 'bg-[#002D9C]/10'}`} />
                <div className={`flex items-center justify-center w-10 h-10 rounded-full font-bold transition-all ${step === 2 ? 'bg-[#002D9C] text-white scale-110' : 'bg-[#002D9C]/20 text-[#002D9C]'}`}>2</div>
              </div>

              <AnimatePresence mode="wait">
                {step === 1 ? (
                  <motion.div
                    key="step1"
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: 20 }}
                    className={`rounded-2xl border p-8 md:p-12 ${cardBg} no-print`}
                  >
                    <div className="mb-10 text-center md:text-left rtl:md:text-right">
                      <h2 className={`text-3xl font-black ${titleColor} mb-2`}>{t('services.personalSection')}</h2>
                      <p className={subTextColor}>Please provide your official information as it appears on your National ID. All fields are required.</p>
                    </div>

                    <div className="space-y-10">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <InputGroup
                          label={t('services.nameAr')}
                          placeholder="الاسم الكامل بالعربية"
                          value={formData.nameAr}
                          error={errors.nameAr}
                          onChange={(val) => setFormData({ ...formData, nameAr: val })}
                          theme={theme}
                          dir="rtl"
                        />
                        <InputGroup
                          label={t('services.nameEn')}
                          placeholder="Full name in English"
                          value={formData.nameEn}
                          error={errors.nameEn}
                          onChange={(val) => setFormData({ ...formData, nameEn: val })}
                          theme={theme}
                        />
                      </div>

                      <div className="space-y-3">
                        <label className={`text-xs font-black uppercase tracking-widest ${theme === 'dark' ? 'text-[#BBE9FF]/70' : 'text-[#001133]/60'}`}>
                          {t('services.nationalId')}
                        </label>
                        <div className="flex flex-wrap gap-1.5 flex-row-reverse" dir="ltr">
                          {formData.nationalId.map((digit, i) => (
                            <input
                              key={i}
                              id={`id-box-${i}`}
                              type="text"
                              maxLength={1}
                              value={digit}
                              onChange={(e) => updateNationalId(i, e.target.value)}
                              className={`w-9 h-12 md:w-10 md:h-14 border-2 text-center text-xl font-bold rounded-md transition-all focus:outline-none focus:border-[#002D9C] ${
                                errors.nationalId ? 'border-red-500' : (theme === 'dark' ? 'bg-white/5 border-white/10 text-white' : 'bg-[#F0F9FF] border-[#002D9C]/10 text-[#001133]')
                              }`}
                            />
                          ))}
                        </div>
                        {errors.nationalId && <p className="text-red-500 text-xs font-bold mt-1 flex items-center gap-1"><AlertCircle size={12}/> {errors.nationalId}</p>}
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        {/* Email with Verification */}
                        <div className="space-y-2">
                          <InputGroup
                            label={t('services.email')}
                            type="email"
                            placeholder="example@domain.com"
                            value={formData.email}
                            error={errors.email}
                            onChange={(val) => { setFormData({ ...formData, email: val }); setIsEmailVerified(false); }}
                            theme={theme}
                            disabled={isEmailVerified}
                          />
                          {!isEmailVerified && !isOtpSent && (
                            <button 
                              onClick={sendEmailOTP}
                              disabled={isSendingOtp}
                              className="w-full py-2 bg-[#002D9C]/10 text-[#002D9C] border border-[#002D9C]/20 rounded-lg text-xs font-bold hover:bg-[#002D9C]/20 transition-all flex items-center justify-center gap-2"
                            >
                              {isSendingOtp ? <Loader2 size={14} className="animate-spin" /> : <Mail size={14} />}
                              Send Verification Code
                            </button>
                          )}
                          {isEmailVerified && (
                             <div className="flex items-center gap-2 text-green-600 font-bold text-xs py-2 bg-green-50 rounded-lg px-3 border border-green-100">
                               <ShieldCheck size={14} /> Email Verified Successfully
                             </div>
                          )}
                          {isOtpSent && !isEmailVerified && (
                            <motion.div 
                              initial={{ opacity: 0, y: 10 }}
                              animate={{ opacity: 1, y: 0 }}
                              className="space-y-3 p-4 bg-white/5 border border-dashed border-[#002D9C]/30 rounded-xl"
                            >
                              <label className="text-[10px] font-black uppercase text-[#002D9C]">Enter 6-Digit OTP</label>
                              <div className="flex gap-2">
                                <input 
                                  type="text" 
                                  maxLength={6}
                                  value={otpCode}
                                  onChange={(e) => setOtpCode(e.target.value)}
                                  placeholder="000000"
                                  className="flex-grow py-3 px-4 border-2 border-[#002D9C]/20 rounded-lg font-mono font-bold tracking-[0.5em] text-center focus:border-[#002D9C] outline-none"
                                />
                                <button 
                                  onClick={verifyEmailOTP}
                                  disabled={isVerifying}
                                  className="px-6 bg-[#002D9C] text-white rounded-lg font-bold text-xs hover:bg-[#001D6E] transition-all flex items-center justify-center"
                                >
                                  {isVerifying ? <Loader2 size={16} className="animate-spin" /> : "Verify"}
                                </button>
                              </div>
                              {errors.otp && <p className="text-red-500 text-[10px] font-bold">{errors.otp}</p>}
                            </motion.div>
                          )}
                        </div>

                        <InputGroup
                          label={t('services.whatsapp')}
                          placeholder="+20 123 456 7890"
                          value={formData.whatsapp}
                          error={errors.whatsapp}
                          onChange={(val) => setFormData({ ...formData, whatsapp: val })}
                          theme={theme}
                        />
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <InputGroup
                          label={t('services.faculty')}
                          placeholder="Enter your faculty name"
                          value={formData.faculty}
                          error={errors.faculty}
                          onChange={(val) => setFormData({ ...formData, faculty: val })}
                          theme={theme}
                        />
                        <div className="space-y-3">
                          <label className={`text-xs font-black uppercase tracking-widest ${theme === 'dark' ? 'text-[#BBE9FF]/70' : 'text-[#001133]/60'}`}>
                            {t('services.univStatus')}
                          </label>
                          <div className="flex flex-col gap-3">
                            <RadioOption 
                              id="status1" 
                              name="univStatus" 
                              label={t('services.status1')} 
                              checked={formData.applicantStatus === t('services.status1')}
                              onChange={() => setFormData({...formData, applicantStatus: t('services.status1')})}
                              theme={theme} 
                            />
                            <RadioOption 
                              id="status2" 
                              name="univStatus" 
                              label={t('services.status2')} 
                              checked={formData.applicantStatus === t('services.status2')}
                              onChange={() => setFormData({...formData, applicantStatus: t('services.status2')})}
                              theme={theme} 
                            />
                            <RadioOption 
                              id="status3" 
                              name="univStatus" 
                              label={t('services.status3')} 
                              checked={formData.applicantStatus === t('services.status3')}
                              onChange={() => setFormData({...formData, applicantStatus: t('services.status3')})}
                              theme={theme} 
                            />
                          </div>
                          {errors.applicantStatus && <p className="text-red-500 text-xs font-bold mt-1">{errors.applicantStatus}</p>}
                        </div>
                      </div>

                      {/* Optional Courses Selection */}
                      <div className="space-y-3">
                        <label className={`text-xs font-black uppercase tracking-widest ${theme === 'dark' ? 'text-[#BBE9FF]/70' : 'text-[#001133]/60'}`}>
                          Optional Courses (Choose 2)
                        </label>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          {['الفصول الافتراضية', 'البحث عبر الانترنت', 'الحوسبة السحابية الشبكات', 'تطبيقات المحمول'].map((course) => (
                            <div 
                              key={course}
                              onClick={() => toggleOptionalCourse(course)}
                              className={`p-4 rounded-xl border-2 cursor-pointer transition-all flex items-center justify-between font-bold text-sm ${
                                formData.optionalCourses.includes(course)
                                  ? 'border-[#002D9C] bg-[#002D9C]/5 text-[#002D9C]'
                                  : (theme === 'dark' ? 'bg-white/5 border-white/10 text-white/40' : 'bg-[#F0F9FF] border-[#002D9C]/10 text-[#001133]/40')
                              }`}
                            >
                              {course}
                              {formData.optionalCourses.includes(course) ? <CheckCircle2 size={18} /> : <div className="w-[18px] h-[18px] border-2 rounded-full border-current opacity-20" />}
                            </div>
                          ))}
                        </div>
                        {errors.optionalCourses && <p className="text-red-500 text-xs font-bold mt-1">{errors.optionalCourses}</p>}
                      </div>

                      <div className="space-y-3">
                        <label className={`text-xs font-black uppercase tracking-widest ${theme === 'dark' ? 'text-[#BBE9FF]/70' : 'text-[#001133]/60'}`}>
                          {t('services.regType')}
                        </label>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                          <SelectCard 
                            id="reg1" 
                            label={t('services.reg1')} 
                            checked={formData.registrationType === t('services.reg1')}
                            onChange={() => setFormData({...formData, registrationType: t('services.reg1')})}
                            theme={theme} 
                          />
                          <SelectCard 
                            id="reg2" 
                            label={t('services.reg2')} 
                            checked={formData.registrationType === t('services.reg2')}
                            onChange={() => setFormData({...formData, registrationType: t('services.reg2')})}
                            theme={theme} 
                          />
                          <SelectCard 
                            id="reg3" 
                            label={t('services.reg3')} 
                            checked={formData.registrationType === t('services.reg3')}
                            onChange={() => setFormData({...formData, registrationType: t('services.reg3')})}
                            theme={theme} 
                          />
                        </div>
                        {errors.registrationType && <p className="text-red-500 text-xs font-bold mt-1">{errors.registrationType}</p>}
                      </div>

                      <div className="pt-10 flex justify-end">
                        <button
                          onClick={handleNext}
                          className={`flex items-center gap-3 px-12 py-5 bg-[#002D9C] text-white rounded-xl font-bold text-lg hover:bg-[#001D6E] transition-all shadow-xl hover:-translate-y-1 group ${!isEmailVerified ? 'opacity-50 cursor-not-allowed grayscale' : ''}`}
                        >
                          Next Step <ArrowRight className="group-hover:translate-x-1 transition-transform" />
                        </button>
                      </div>
                    </div>
                  </motion.div>
                ) : (
                  <motion.div
                    key="step2"
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 1.05 }}
                    className="space-y-8 no-print"
                  >
                    <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
                      <button
                        onClick={handleBackToStep1}
                        className={`flex items-center gap-2 px-6 py-3 rounded-xl font-bold transition-all border ${
                          theme === 'dark' ? 'bg-white/5 border-white/10 text-white hover:bg-white/10' : 'bg-white border-[#002D9C]/20 text-[#002D9C] hover:bg-[#F0F9FF]'
                        }`}
                      >
                        <Edit3 size={18} /> Edit Information
                      </button>
                      <div className="flex gap-4">
                        <button onClick={() => window.print()} className="flex items-center gap-2 px-6 py-3 bg-[#001133] text-white rounded-xl font-bold hover:bg-black transition-all shadow-lg">
                          <Printer size={18} /> Print Form
                        </button>
                        <button onClick={() => window.print()} className="flex items-center gap-2 px-6 py-3 bg-[#002D9C] text-white rounded-xl font-bold hover:bg-[#001D6E] transition-all shadow-lg">
                          <Download size={18} /> Download PDF
                        </button>
                      </div>
                    </div>

                    <div className="overflow-x-auto pb-10">
                       <div className="mx-auto bg-gray-500 p-10 min-w-[850px] flex justify-center">
                          <OfficialFayoumForm data={formData} />
                       </div>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>

              <div className="hidden print:block">
                 <OfficialFayoumForm data={formData} />
              </div>
            </div>
          )}
        </AnimatePresence>
      </div>

      <style>{`
        @media print {
          @page { size: A4 portrait; margin: 0; }
          body { background: white !important; margin: 0 !important; padding: 0 !important; }
          .no-print { display: none !important; }
          header, footer, canvas { display: none !important; }
        }
      `}</style>
    </div>
  );
};

const OfficialFayoumForm: React.FC<{ data: RegistrationData }> = ({ data }) => (
  <div dir="rtl" className="bg-white text-black p-[15mm] w-[210mm] min-h-[297mm] mx-auto shadow-none print:shadow-none print:border-none border border-gray-300 flex flex-col font-serif" style={{ color: '#000', fontFamily: "'Amiri', 'Traditional Arabic', serif" }}>

