      className={`w-full border-2 rounded-xl py-4 px-5 transition-all font-medium ${
        error ? 'border-red-500 bg-red-50/5' : (theme === 'dark' ? 'bg-white/5 border-white/10 text-white focus:border-[#BBE9FF]' : 'bg-[#F0F9FF] border-[#002D9C]/10 text-[#001133] focus:border-[#002D9C]')
      } ${disabled ? 'opacity-50 bg-gray-50 cursor-not-allowed' : ''}`}
