};

export default Services;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Edit3, 
  ArrowRight, 
  ArrowLeft, 
  Printer, 
  Download, 
  AlertCircle, 
  CheckSquare, 
  Square, 
  RefreshCcw, 
  UserPlus, 
  CheckCircle2, 
  ShieldCheck, 
  Loader2,
  Mail,
  Lock
} from 'lucide-react';
import { useLanguage } from '../LanguageContext';
import { useTheme } from '../ThemeContext';
import { supabase } from '../supabaseClient';
import { translations } from '../translations';

type RegistrationData = {
  nameAr: string;
  nameEn: string;
  nationalId: string[];
  email: string;
  whatsapp: string;
  faculty: string;
  applicantStatus: string;
  registrationType: string;
  optionalCourses: string[];
};

type ViewMode = 'selection' | 'registration' | 'reapply';

const Services: React.FC = () => {
  // Force Arabic strings for this page
  const text = translations.ar;
  const { theme } = useTheme();
  const [view, setView] = useState<ViewMode>('selection');
  const [step, setStep] = useState(1);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [todayDate] = useState(new Date().toLocaleDateString('en-GB')); // DD/MM/YYYY

  // Verification States
  const [isEmailVerified, setIsEmailVerified] = useState(false);
  const [isOtpSent, setIsOtpSent] = useState(false);
  const [otpCode, setOtpCode] = useState('');
  const [isSendingOtp, setIsSendingOtp] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);

  const [formData, setFormData] = useState<RegistrationData>({
    nameAr: '',
    nameEn: '',
    nationalId: Array(14).fill(''),
    email: '',
    whatsapp: '',
    faculty: '',
    applicantStatus: '',
    registrationType: '',
    optionalCourses: [],
  });

  const titleColor = theme === 'dark' ? 'text-slate-100' : 'text-[#001133]';
  const subTextColor = theme === 'dark' ? 'text-slate-300' : 'text-[#001133]/60';
  const cardBg = theme === 'dark' ? 'bg-slate-800 border-slate-700 shadow-2xl' : 'bg-white border-[#002D9C]/10 shadow-xl';
  const inputBg = theme === 'dark' ? 'bg-slate-900 border-slate-700 text-slate-100' : 'bg-[#F0F9FF] border-[#002D9C]/10 text-[#001133]';

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.nameAr.trim()) newErrors.nameAr = "مطلوب";
    if (!formData.nameEn.trim()) newErrors.nameEn = "مطلوب";
    if (formData.nationalId.some(d => d === '')) newErrors.nationalId = "يرجى إكمال الرقم القومي";
    if (!formData.email.trim() || !formData.email.includes('@')) newErrors.email = "بريد إلكتروني غير صالح";
    if (!formData.whatsapp.trim()) newErrors.whatsapp = "مطلوب";
    if (!formData.faculty.trim()) newErrors.faculty = "مطلوب";
    if (!formData.applicantStatus) newErrors.applicantStatus = "يرجى اختيار الصفة";
    if (!formData.registrationType) newErrors.registrationType = "يرجى اختيار نوع التسجيل";
    if (formData.optionalCourses.length !== 2) newErrors.optionalCourses = "يرجى اختيار مقررين فقط";
    if (!isEmailVerified) newErrors.email = "يجب التحقق من البريد الإلكتروني أولاً";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (validate()) {
      setStep(2);
      window.scrollTo(0, 0);
    }
  };

  const handleBackToStep1 = () => {
    setStep(1);
    window.scrollTo(0, 0);
  };

  const handleBackToSelection = () => {
    setView('selection');
    setStep(1);
    window.scrollTo(0, 0);
  };

  const updateNationalId = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newId = [...formData.nationalId];
    newId[index] = value.slice(-1);
    setFormData({ ...formData, nationalId: newId });

    if (value && index < 13) {
      const nextInput = document.getElementById(`id-box-${index + 1}`);
      nextInput?.focus();
    }
  };

  const toggleOptionalCourse = (course: string) => {
    setFormData(prev => {
      if (prev.optionalCourses.includes(course)) {
        return { ...prev, optionalCourses: prev.optionalCourses.filter(c => c !== course) };
      }
      if (prev.optionalCourses.length < 2) {
        return { ...prev, optionalCourses: [...prev.optionalCourses, course] };
      }
      return prev;
    });
  };

  async function sendEmailOTP() {
    if (!formData.email || !formData.email.includes('@')) {
      setErrors({ ...errors, email: "يرجى إدخال بريد إلكتروني صالح" });
      return;
    }
    setIsSendingOtp(true);
    try {
      const { error } = await supabase.auth.signInWithOtp({
        email: formData.email,
        options: { shouldCreateUser: true }
      });
      if (error) throw error;
      setIsOtpSent(true);
      setErrors({});
    } catch (err: any) {
      setErrors({ email: err.message });
    } finally {
      setIsSendingOtp(false);
    }
  }

  async function verifyEmailOTP() {
    if (otpCode.length !== 6) {
      setErrors({ otp: "يجب إدخال 6 أرقام" });
      return;
    }
    setIsVerifying(true);
    try {
      const { data, error } = await supabase.auth.verifyOtp({
        email: formData.email,
        token: otpCode,
        type: 'email'
      });
      if (error) throw error;
      if (data) {
        setIsEmailVerified(true);
        setIsOtpSent(false);
      }
    } catch (err: any) {
      setErrors({ otp: "رمز غير صحيح أو منتهي الصلاحية" });
    } finally {
      setIsVerifying(false);
    }
  }

  return (
    <div dir="rtl" className="relative pt-32 pb-20 px-4 md:px-6 min-h-screen font-sans selection:bg-blue-500/30">
      <div className="max-w-5xl mx-auto">
        <AnimatePresence mode="wait">
          {view === 'selection' ? (
            <motion.div
              key="selection"
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="text-center"
            >
              <h1 className={`text-4xl md:text-6xl font-black ${titleColor} mb-4 tracking-tight`}>
                {text.services.initialTitle}
              </h1>
              <p className={`${subTextColor} text-lg max-w-2xl mx-auto mb-16 font-medium`}>
                {text.services.initialSub}
              </p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl mx-auto">
                <SelectionCard
                  title={text.services.opt1Title}
                  description={text.services.opt1Desc}
                  buttonText={text.services.opt1Btn}
                  icon={<UserPlus size={32} className="text-[#002D9C]" />}
                  onClick={() => setView('registration')}
                  theme={theme}
                  accent="primary"
                />
                <SelectionCard
                  title={text.services.opt2Title}
                  description={text.services.opt2Desc}
                  buttonText={text.services.opt2Btn}
                  icon={<RefreshCcw size={32} className="text-[#0091EA]" />}
                  onClick={() => setView('reapply')}
                  theme={theme}
                  accent="secondary"
                />
              </div>
            </motion.div>
          ) : view === 'reapply' ? (
            <motion.div
              key="reapply"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              className={`rounded-3xl border p-8 md:p-12 ${cardBg}`}
            >
              <button onClick={handleBackToSelection} className="flex items-center gap-2 text-sm font-bold text-[#002D9C] mb-8 hover:underline">
                <ArrowRight size={16} /> {text.services.back}
              </button>
              <div className="text-center max-w-2xl mx-auto">
                <h2 className={`text-3xl md:text-4xl font-black ${titleColor} mb-4`}>{text.services.reapplyTitle}</h2>
                <p className={`${subTextColor} mb-12`}>{text.services.reapplySub}</p>
                <div className="space-y-6">
                  <InputGroup
                    label={text.services.nationalId}
                    placeholder="2990101XXXXXXXXX"
                    value=""
                    onChange={() => {}}
                    theme={theme}
                    inputBg={inputBg}
                  />
                  <button className="w-full py-5 bg-[#002D9C] text-white rounded-2xl font-bold text-lg hover:bg-[#001D6E] transition-all shadow-lg active:scale-95">
                    {text.services.opt2Btn}
                  </button>
                </div>
              </div>
            </motion.div>
          ) : (
            <div key="registration-flow">
              <div className="flex justify-center mb-12 no-print items-center gap-4">
                <button onClick={handleBackToSelection} className="ml-4 p-2 rounded-full hover:bg-gray-100 transition-colors" title="رجوع">
                  <ArrowRight size={24} className="text-[#002D9C]" />
                </button>
                <div className={`flex items-center justify-center w-10 h-10 rounded-full font-bold transition-all ${step === 1 ? 'bg-[#002D9C] text-white scale-110' : 'bg-[#002D9C]/20 text-[#002D9C]'}`}>١</div>
                <div className={`h-1 w-16 rounded-full transition-all ${step === 2 ? 'bg-[#002D9C]' : 'bg-[#002D9C]/10'}`} />
                <div className={`flex items-center justify-center w-10 h-10 rounded-full font-bold transition-all ${step === 2 ? 'bg-[#002D9C] text-white scale-110' : 'bg-[#002D9C]/20 text-[#002D9C]'}`}>٢</div>
              </div>

              <AnimatePresence mode="wait">
                {step === 1 ? (
                  <motion.div
                    key="step1"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className={`rounded-3xl border p-6 md:p-12 ${cardBg} no-print`}
                  >
                    <div className="mb-10 text-right">
                      <h2 className={`text-2xl md:text-3xl font-black ${titleColor} mb-2`}>{text.services.personalSection}</h2>
                      <p className={subTextColor}>يرجى إدخال البيانات بدقة. التحقق من البريد الإلكتروني إلزامي.</p>
                    </div>

                    <div className="space-y-10">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <InputGroup
                          label="الاسم الرباعي (بالعربية)"
                          placeholder="مثال: محمد أحمد علي حسن"
                          value={formData.nameAr}
                          error={errors.nameAr}
                          onChange={(val) => setFormData({ ...formData, nameAr: val })}
                          theme={theme}
                          inputBg={inputBg}
                        />
                        <InputGroup
                          label="الاسم الرباعي (بالإنجليزية)"
                          placeholder="Example: Mohamed Ahmed Ali Hassan"
                          value={formData.nameEn}
                          error={errors.nameEn}
                          onChange={(val) => setFormData({ ...formData, nameEn: val })}
                          theme={theme}
                          inputBg={inputBg}
                          dir="ltr"
                        />
                      </div>

                      <div className="space-y-3">
                        <label className={`text-sm font-black uppercase tracking-widest ${theme === 'dark' ? 'text-slate-400' : 'text-[#001133]/60'}`}>
                          {text.services.nationalId}
                        </label>
                        <div className="flex flex-wrap gap-2 flex-row-reverse" dir="ltr">
                          {formData.nationalId.map((digit, i) => (
                            <input
                              key={i}
                              id={`id-box-${i}`}
                              type="text"
                              maxLength={1}
                              value={digit}
                              onChange={(e) => updateNationalId(i, e.target.value)}
                              className={`w-9 h-12 md:w-11 md:h-14 border-2 text-center text-xl font-bold rounded-xl transition-all focus:outline-none focus:ring-2 focus:ring-[#002D9C] ${
                                errors.nationalId ? 'border-red-500' : inputBg
                              }`}
                            />
                          ))}
                        </div>
                        {errors.nationalId && <p className="text-red-500 text-xs font-bold mt-2 flex items-center gap-1"><AlertCircle size={14}/> {errors.nationalId}</p>}
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="space-y-4">
                          <InputGroup
                            label={text.services.email}
                            type="email"
                            placeholder="user@example.com"
                            value={formData.email}
                            error={errors.email}
                            onChange={(val) => { setFormData({ ...formData, email: val }); setIsEmailVerified(false); setIsOtpSent(false); }}
                            theme={theme}
                            inputBg={inputBg}
                            disabled={isEmailVerified}
                          />
                          {!isEmailVerified && !isOtpSent && (
                            <button 
                              onClick={sendEmailOTP}
                              disabled={isSendingOtp}
                              className="w-full py-3 bg-[#002D9C] text-white rounded-xl font-bold text-sm hover:bg-[#001D6E] transition-all flex items-center justify-center gap-2 shadow-md active:scale-95 disabled:opacity-50"
                            >
                              {isSendingOtp ? <Loader2 size={18} className="animate-spin" /> : <Mail size={18} />}
                              إرسال رمز التحقق
                            </button>
                          )}
                          {isEmailVerified && (
                             <div className="flex items-center gap-3 text-emerald-500 font-bold text-sm py-3 px-4 bg-emerald-500/10 rounded-xl border border-emerald-500/20">
                               <ShieldCheck size={20} /> تم التحقق من البريد بنجاح
                             </div>
                          )}
                          {isOtpSent && !isEmailVerified && (
                            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="space-y-4 p-5 bg-blue-500/5 border border-dashed border-[#002D9C]/30 rounded-2xl">
                              <label className="text-xs font-black uppercase text-[#002D9C]">أدخل الرمز المكون من ٦ أرقام</label>
                              <div className="flex gap-2">
                                <input 
                                  type="text" maxLength={6} value={otpCode}
                                  onChange={(e) => setOtpCode(e.target.value)}
                                  placeholder="000000"
                                  className={`flex-grow py-3 px-4 border-2 rounded-xl font-mono font-bold tracking-[0.4em] text-center focus:outline-none focus:ring-2 focus:ring-[#002D9C] ${inputBg}`}
                                />
                                <button onClick={verifyEmailOTP} disabled={isVerifying} className="px-6 bg-[#002D9C] text-white rounded-xl font-bold text-sm hover:bg-[#001D6E] transition-all">
                                  {isVerifying ? <Loader2 size={18} className="animate-spin" /> : "تحقق"}
                                </button>
                              </div>
                              {errors.otp && <p className="text-red-500 text-xs font-bold">{errors.otp}</p>}
                            </motion.div>
                          )}
                        </div>

                        <InputGroup
                          label={text.services.whatsapp}
                          placeholder="+20 1XX XXX XXXX"
                          value={formData.whatsapp}
                          error={errors.whatsapp}
                          onChange={(val) => setFormData({ ...formData, whatsapp: val })}
                          theme={theme}
                          inputBg={inputBg}
                          dir="ltr"
                        />
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <InputGroup
                          label={text.services.faculty}
                          placeholder="أدخل اسم الكلية"
                          value={formData.faculty}
                          error={errors.faculty}
                          onChange={(val) => setFormData({ ...formData, faculty: val })}
                          theme={theme}
                          inputBg={inputBg}
                        />
                        <div className="space-y-4">
                          <label className={`text-sm font-black uppercase tracking-widest ${theme === 'dark' ? 'text-slate-400' : 'text-[#001133]/60'}`}>
                            {text.services.univStatus}
                          </label>
                          <div className="flex flex-col gap-4">
                            <RadioOption id="status1" name="univStatus" label={text.services.status1} checked={formData.applicantStatus === text.services.status1} onChange={() => setFormData({...formData, applicantStatus: text.services.status1})} theme={theme} />
                            <RadioOption id="status2" name="univStatus" label={text.services.status2} checked={formData.applicantStatus === text.services.status2} onChange={() => setFormData({...formData, applicantStatus: text.services.status2})} theme={theme} />
                            <RadioOption id="status3" name="univStatus" label={text.services.status3} checked={formData.applicantStatus === text.services.status3} onChange={() => setFormData({...formData, applicantStatus: text.services.status3})} theme={theme} />
                          </div>
                        </div>
