import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Edit3, 
  ArrowRight, 
  ArrowLeft, 
  Printer, 
  Download, 
  AlertCircle, 
  CheckSquare, 
  Square, 
  RefreshCcw, 
  UserPlus, 
  CheckCircle2, 
  ShieldCheck, 
  Loader2,
  Mail,
  Lock
} from 'lucide-react';
import { useLanguage } from '../LanguageContext';
import { useTheme } from '../ThemeContext';
import { supabase } from '../supabaseClient';
import { translations } from '../translations';

type RegistrationData = {
  nameAr: string;
  nameEn: string;
  nationalId: string[];
  email: string;
  whatsapp: string;
  faculty: string;
  applicantStatus: string;
  registrationType: string;
  optionalCourses: string[];
};

type ViewMode = 'selection' | 'registration' | 'reapply';

const Services: React.FC = () => {
  // Force Arabic strings for this page
  const text = translations.ar;
  const { theme } = useTheme();
  const [view, setView] = useState<ViewMode>('selection');
  const [step, setStep] = useState(1);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [todayDate] = useState(new Date().toLocaleDateString('en-GB')); // DD/MM/YYYY

  // Verification States
  const [isEmailVerified, setIsEmailVerified] = useState(false);
  const [isOtpSent, setIsOtpSent] = useState(false);
  const [otpCode, setOtpCode] = useState('');
  const [isSendingOtp, setIsSendingOtp] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);

  const [formData, setFormData] = useState<RegistrationData>({
    nameAr: '',
    nameEn: '',
    nationalId: Array(14).fill(''),
    email: '',
    whatsapp: '',
    faculty: '',
    applicantStatus: '',
    registrationType: '',
    optionalCourses: [],
  });

  const titleColor = theme === 'dark' ? 'text-[#E5E7EB]' : 'text-[#001133]';
  const subTextColor = theme === 'dark' ? 'text-[#94A3B8]' : 'text-[#001133]/60';
  const cardBg = theme === 'dark' ? 'bg-[#1E293B] border-slate-700 shadow-2xl' : 'bg-white border-[#002D9C]/10 shadow-xl';
  const inputBg = theme === 'dark' ? 'bg-[#0F172A] border-slate-700 text-[#E5E7EB]' : 'bg-[#F0F9FF] border-[#002D9C]/10 text-[#001133]';

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.nameAr.trim()) newErrors.nameAr = "مطلوب";
    if (!formData.nameEn.trim()) newErrors.nameEn = "مطلوب";
    if (formData.nationalId.some(d => d === '')) newErrors.nationalId = "يرجى إكمال الرقم القومي";
    if (!formData.email.trim() || !formData.email.includes('@')) newErrors.email = "بريد إلكتروني غير صالح";
    if (!formData.whatsapp.trim()) newErrors.whatsapp = "مطلوب";
    if (!formData.faculty.trim()) newErrors.faculty = "مطلوب";
    if (!formData.applicantStatus) newErrors.applicantStatus = "يرجى اختيار الصفة";
    if (!formData.registrationType) newErrors.registrationType = "يرجى اختيار نوع التسجيل";
    if (formData.optionalCourses.length !== 2) newErrors.optionalCourses = "يرجى اختيار مقررين فقط";
    if (!isEmailVerified) newErrors.email = "يجب التحقق من البريد الإلكتروني أولاً";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (validate()) {
      setStep(2);
      window.scrollTo(0, 0);
    }
  };

  const handleBackToStep1 = () => {
    setStep(1);
    window.scrollTo(0, 0);
  };

  const handleBackToSelection = () => {
    setView('selection');
    setStep(1);
    window.scrollTo(0, 0);
  };

  const updateNationalId = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newId = [...formData.nationalId];
    newId[index] = value.slice(-1);
    setFormData({ ...formData, nationalId: newId });

    if (value && index < 13) {
      const nextInput = document.getElementById(`id-box-${index + 1}`);
      nextInput?.focus();
    }
  };

  const toggleOptionalCourse = (course: string) => {
    setFormData(prev => {
      if (prev.optionalCourses.includes(course)) {
        return { ...prev, optionalCourses: prev.optionalCourses.filter(c => c !== course) };
      }
      if (prev.optionalCourses.length < 2) {
        return { ...prev, optionalCourses: [...prev.optionalCourses, course] };
      }
      return prev;
    });
  };

  async function sendEmailOTP() {
    if (!formData.email || !formData.email.includes('@')) {
      setErrors({ ...errors, email: "يرجى إدخال بريد إلكتروني صالح" });
      return;
    }
    setIsSendingOtp(true);
    try {
      const { error } = await supabase.auth.signInWithOtp({
        email: formData.email,
        options: { shouldCreateUser: true }
      });
      if (error) throw error;
      setIsOtpSent(true);
      setErrors({});
    } catch (err: any) {
      setErrors({ email: err.message });
    } finally {
      setIsSendingOtp(false);
    }
  }

  async function verifyEmailOTP() {
    if (otpCode.length !== 6) {
      setErrors({ otp: "يجب إدخال 6 أرقام" });
      return;
    }
    setIsVerifying(true);
    try {
      const { data, error } = await supabase.auth.verifyOtp({
        email: formData.email,
        token: otpCode,
        type: 'email'
      });
      if (error) throw error;
      if (data) {
        setIsEmailVerified(true);
        setIsOtpSent(false);
      }
    } catch (err: any) {
      setErrors({ otp: "رمز غير صحيح أو منتهي الصلاحية" });
    } finally {
      setIsVerifying(false);
    }
  }

