    <AnimatedSection className={`${cardBg} border p-8 rounded-3xl hover:-translate-y-2 hover:shadow-2xl transition-all ${language === 'ar' ? 'text-right' : 'text-left'}`}>
      <div className={`w-12 h-12 rounded-xl border flex items-center justify-center mb-6 ${language === 'ar' ? 'mr-0 ml-auto' : ''} ${
        theme === 'dark' ? 'bg-slate-900 border-slate-700 shadow-inner' : 'bg-[#E1F5FE] border-[#002D9C]/10 shadow-sm'
      }`}>
        {icon}
      </div>
      <h4 className={`text-xl font-bold mb-3 ${titleColor}`}>{title}</h4>
      <p className={`font-medium leading-relaxed mb-6 ${subTextColor}`}>{desc}</p>
      <button className={`font-extrabold flex items-center gap-2 group rtl:flex-row-reverse rtl:justify-end ${
        theme === 'dark' ? 'text-[#38BDF8] hover:text-[#60A5FA]' : 'text-[#002D9C] hover:text-[#001D6E]'
      }`}>
        {btnText} <span className={`${language === 'ar' ? 'group-hover:-translate-x-1' : 'group-hover:translate-x-1'} transition-transform`}>{language === 'ar' ? '←' : '→'}</span>
      </button>
    </AnimatedSection>
  );
};

