const SelectionCard: React.FC<{ title: string; description: string; buttonText: string; icon: React.ReactNode; onClick: () => void; theme: string; accent: 'primary' | 'secondary' }> = ({ title, description, buttonText, icon, onClick, theme, accent }) => {
  const cardBg = theme === 'dark' ? 'bg-[#1E293B] border-slate-700 shadow-2xl' : 'bg-white border-[#002D9C]/10 shadow-lg';
  const accentColor = accent === 'primary' 
    ? (theme === 'dark' ? 'bg-[#38BDF8] hover:bg-[#60A5FA] text-slate-900' : 'bg-[#002D9C] hover:bg-[#001D6E] text-white') 
    : (theme === 'dark' ? 'bg-slate-700 hover:bg-slate-600 text-[#E5E7EB]' : 'bg-[#0091EA] hover:bg-[#007AB8] text-white');

  // Define color constants that were previously missing in this component scope
  const titleColor = theme === 'dark' ? 'text-[#E5E7EB]' : 'text-[#001133]';
  const subTextColor = theme === 'dark' ? 'text-[#94A3B8]' : 'text-[#001133]/60';

  return (
    <motion.div whileHover={{ y: -8, boxShadow: '0 25px 50px -12px rgba(0,0,0,0.4)' }} className={`p-10 rounded-[40px] border flex flex-col items-center text-center transition-all ${cardBg}`}>
