    whatsapp: '',
    faculty: '',
    applicantStatus: '',
    registrationType: '',
    optionalCourses: [],
  });

  const titleColor = theme === 'dark' ? 'text-[#E5E7EB]' : 'text-[#001133]';
  const subTextColor = theme === 'dark' ? 'text-[#94A3B8]' : 'text-[#001133]/60';
  const cardBg = theme === 'dark' ? 'bg-[#1E293B] border-slate-700 shadow-2xl' : 'bg-white border-[#002D9C]/10 shadow-xl';
  const inputBg = theme === 'dark' ? 'bg-[#0F172A] border-slate-700 text-[#E5E7EB]' : 'bg-[#F0F9FF] border-[#002D9C]/10 text-[#001133]';

  const validate = () => {
    const newErrors: Record<string, string> = {};

    if (!formData.nameAr.trim()) {
      newErrors.nameAr = "مطلوب";
    } else if (!/^[\u0600-\u06FF\s]+$/.test(formData.nameAr)) {
      newErrors.nameAr = "يجب إدخال حروف عربية فقط";
    }

    if (!formData.nameEn.trim()) {
      newErrors.nameEn = "مطلوب";
    } else if (!/^[a-zA-Z\s]+$/.test(formData.nameEn)) {
      newErrors.nameEn = "يجب إدخال حروف إنجليزية فقط";
    }

    if (formData.nationalId.some(d => d === '')) newErrors.nationalId = "يرجى إكمال الرقم القومي";
    if (!formData.email.trim() || !formData.email.includes('@')) newErrors.email = "بريد إلكتروني غير صالح";
    if (!formData.whatsapp.trim()) newErrors.whatsapp = "مطلوب";
    if (!formData.faculty.trim()) newErrors.faculty = "مطلوب";
    if (!formData.applicantStatus) newErrors.applicantStatus = "يرجى اختيار الصفة";
    if (!formData.registrationType) newErrors.registrationType = "يرجى اختيار نوع التسجيل";
    if (formData.optionalCourses.length !== 2) newErrors.optionalCourses = "يرجى اختيار مقررين فقط";
    if (!isEmailVerified) newErrors.email = "يجب التحقق من البريد الإلكتروني أولاً";

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (validate()) {
      setStep(2);
      window.scrollTo(0, 0);
    }
  };

  const handleBackToStep1 = () => {
    setStep(1);
    window.scrollTo(0, 0);
  };

  const handleBackToSelection = () => {
    setView('selection');
    setStep(1);
    window.scrollTo(0, 0);
  };

  const updateNationalId = (index: number, value: string) => {
    if (!/^\d*$/.test(value)) return;
    const newId = [...formData.nationalId];
    newId[index] = value.slice(-1);
    setFormData({ ...formData, nationalId: newId });

    if (value && index < 13) {
      const nextInput = document.getElementById(`id-box-${index + 1}`);
      nextInput?.focus();
    }
  };

  const toggleOptionalCourse = (course: string) => {
    setFormData(prev => {
      if (prev.optionalCourses.includes(course)) {
        return { ...prev, optionalCourses: prev.optionalCourses.filter(c => c !== course) };
      }
      if (prev.optionalCourses.length < 2) {
        return { ...prev, optionalCourses: [...prev.optionalCourses, course] };
      }
      return prev;
    });
  };

  async function sendEmailOTP() {
    if (!formData.email || !formData.email.includes('@')) {
      setErrors({ ...errors, email: "يرجى إدخال بريد إلكتروني صالح" });
      return;
    }
    setIsSendingOtp(true);
    try {
      const { error } = await supabase.auth.signInWithOtp({
        email: formData.email,
        options: { shouldCreateUser: true }
      });
      if (error) throw error;
      setIsOtpSent(true);
      setErrors({});
    } catch (err: any) {
      setErrors({ email: err.message });
    } finally {
      setIsSendingOtp(false);
    }
  }

  async function verifyEmailOTP() {
    if (otpCode.length !== 6) {
      setErrors({ otp: "يجب إدخال 6 أرقام" });
      return;
    }
    setIsVerifying(true);
    try {
      const { data, error } = await supabase.auth.verifyOtp({
        email: formData.email,
        token: otpCode,
        type: 'email'
      });
      if (error) throw error;
      if (data) {
        setIsEmailVerified(true);
        setIsOtpSent(false);
      }
    } catch (err: any) {
      setErrors({ otp: "رمز غير صحيح أو منتهي الصلاحية" });
    } finally {
      setIsVerifying(false);
    }
  }

  return (
    <div dir="rtl" className="relative pt-32 pb-20 px-4 md:px-6 min-h-screen font-sans selection:bg-blue-500/30">
      <div className="max-w-5xl mx-auto">
        <AnimatePresence mode="wait">
          {view === 'selection' ? (
            <motion.div
              key="selection"
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="text-center"
            >
              <h1 className={`text-4xl md:text-6xl font-black ${titleColor} mb-4 tracking-tight`}>
                {text.services.initialTitle}
              </h1>
              <p className={`${subTextColor} text-lg max-w-2xl mx-auto mb-16 font-medium`}>
                {text.services.initialSub}
              </p>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl mx-auto">
                <SelectionCard
                  title={text.services.opt1Title}
                  description={text.services.opt1Desc}
                  buttonText={text.services.opt1Btn}
                  icon={<UserPlus size={32} className={theme === 'dark' ? "text-[#38BDF8]" : "text-[#002D9C]"} />}
                  onClick={() => setView('registration')}
                  theme={theme}
                  accent="primary"
                />
                <SelectionCard
                  title={text.services.opt2Title}
                  description={text.services.opt2Desc}
                  buttonText={text.services.opt2Btn}
                  icon={<RefreshCcw size={32} className={theme === 'dark' ? "text-[#60A5FA]" : "text-[#0091EA]"} />}
                  onClick={() => setView('reapply')}
                  theme={theme}
                  accent="secondary"
                />
              </div>
            </motion.div>
          ) : view === 'reapply' ? (
            <motion.div
              key="reapply"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              className={`rounded-3xl border p-8 md:p-12 ${cardBg}`}
            >
              <button onClick={handleBackToSelection} className={`flex items-center gap-2 text-sm font-bold ${theme === 'dark' ? 'text-[#38BDF8]' : 'text-[#002D9C]'} mb-8 hover:underline`}>
                <ArrowRight size={16} /> {text.services.back}
              </button>
              <div className="text-center max-w-2xl mx-auto">
                <h2 className={`text-3xl md:text-4xl font-black ${titleColor} mb-4`}>{text.services.reapplyTitle}</h2>
                <p className={`${subTextColor} mb-12`}>{text.services.reapplySub}</p>
                <div className="space-y-6 text-right">
                  <InputGroup
                    label={text.services.nationalId}
                    placeholder="2990101XXXXXXXXX"
                    value=""
                    onChange={() => {}}
                    theme={theme}
                    inputBg={inputBg}
                  />
                  <button className={`w-full py-5 ${theme === 'dark' ? 'bg-[#38BDF8] text-slate-900 hover:bg-[#60A5FA]' : 'bg-[#002D9C] text-white hover:bg-[#001D6E]'} rounded-2xl font-bold text-lg transition-all shadow-lg active:scale-95`}>
                    {text.services.opt2Btn}
                  </button>
                </div>
              </div>
            </motion.div>
          ) : (
            <div key="registration-flow">
              <div className="flex justify-center mb-12 no-print items-center gap-4">
                <button onClick={handleBackToSelection} className={`ml-4 p-2 rounded-full ${theme === 'dark' ? 'hover:bg-slate-800' : 'hover:bg-gray-100'} transition-colors`} title="رجوع">
                  <ArrowRight size={24} className={theme === 'dark' ? "text-[#38BDF8]" : "text-[#002D9C]"} />
                </button>
                <div className={`flex items-center justify-center w-10 h-10 rounded-full font-bold transition-all ${step === 1 ? (theme === 'dark' ? 'bg-[#38BDF8] text-slate-900' : 'bg-[#002D9C] text-white') + ' scale-110' : (theme === 'dark' ? 'bg-slate-800 text-slate-400' : 'bg-[#002D9C]/20 text-[#002D9C]')}`}>١</div>
                <div className={`h-1 w-16 rounded-full transition-all ${step === 2 ? (theme === 'dark' ? 'bg-[#38BDF8]' : 'bg-[#002D9C]') : (theme === 'dark' ? 'bg-slate-800' : 'bg-[#002D9C]/10')}`} />
                <div className={`flex items-center justify-center w-10 h-10 rounded-full font-bold transition-all ${step === 2 ? (theme === 'dark' ? 'bg-[#38BDF8] text-slate-900' : 'bg-[#002D9C] text-white') + ' scale-110' : (theme === 'dark' ? 'bg-slate-800 text-slate-400' : 'bg-[#002D9C]/20 text-[#002D9C]')}`}>٢</div>
              </div>

              <AnimatePresence mode="wait">
                {step === 1 ? (
                  <motion.div
                    key="step1"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className={`rounded-3xl border p-6 md:p-12 ${cardBg} no-print`}
                  >
                    <div className="mb-10 text-right">
                      <h2 className={`text-2xl md:text-3xl font-black ${titleColor} mb-2`}>{text.services.personalSection}</h2>
                      <p className={subTextColor}>يرجى إدخال البيانات بدقة. التحقق من البريد الإلكتروني إلزامي.</p>
                    </div>

                    <div className="space-y-10">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <InputGroup
                          label="الاسم الرباعي (بالعربية)"
                          placeholder="محمد منصور أحمد محمد"
                          value={formData.nameAr}
                          error={errors.nameAr}
                          onChange={(val) => setFormData({ ...formData, nameAr: val })}
                          theme={theme}
                          inputBg={inputBg}
                        />
                        <InputGroup
                          label="الاسم الرباعي (بالإنجليزية)"
                          placeholder="Mohamed Mansour Ahmed Mohamed"
                          value={formData.nameEn}
                          error={errors.nameEn}
                          onChange={(val) => setFormData({ ...formData, nameEn: val })}
                          theme={theme}
                          inputBg={inputBg}
                          dir="ltr"
                        />
                      </div>

                      <div className="space-y-3 text-right">
                        <label className={`text-sm font-black uppercase tracking-widest ${theme === 'dark' ? 'text-[#94A3B8]' : 'text-[#001133]/60'}`}>
                          {text.services.nationalId}
                        </label>
                        <div className="flex flex-wrap gap-2 justify-end" dir="rtl">
                          {formData.nationalId.map((digit, i) => (
                            <input
                              key={i}
                              id={`id-box-${i}`}
                              type="text"
                              maxLength={1}
                              value={digit}
                              onChange={(e) => updateNationalId(i, e.target.value)}
                              className={`w-9 h-12 md:w-11 md:h-14 border-2 text-center text-xl font-bold rounded-xl transition-all focus:outline-none focus:ring-2 ${theme === 'dark' ? 'focus:ring-[#38BDF8] border-slate-700' : 'focus:ring-[#002D9C] border-[#002D9C]/10'} ${
                                errors.nationalId ? 'border-red-500' : inputBg
                              }`}
                            />
                          ))}
                        </div>
                        {errors.nationalId && <p className="text-red-500 text-xs font-bold mt-2 flex items-center gap-1"><AlertCircle size={14}/> {errors.nationalId}</p>}
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="space-y-4">
                          <InputGroup
                            label={text.services.email}
                            type="email"
                            placeholder="user@example.com"
                            value={formData.email}
                            error={errors.email}
                            onChange={(val) => { setFormData({ ...formData, email: val }); setIsEmailVerified(false); setIsOtpSent(false); }}
                            theme={theme}
                            inputBg={inputBg}
                            disabled={isEmailVerified}
                          />
                          {!isEmailVerified && !isOtpSent && (
                            <button 
                              onClick={sendEmailOTP}
                              disabled={isSendingOtp}
                              className={`w-full py-3 ${theme === 'dark' ? 'bg-slate-700 text-[#38BDF8] border-slate-600' : 'bg-[#002D9C] text-white'} border rounded-xl font-bold text-sm transition-all flex items-center justify-center gap-2 shadow-md active:scale-95 disabled:opacity-50`}
                            >
                              {isSendingOtp ? <Loader2 size={18} className="animate-spin" /> : <Mail size={18} />}
                              إرسال رمز التحقق
                            </button>
                          )}
                          {isEmailVerified && (
                             <div className={`flex items-center gap-3 font-bold text-sm py-3 px-4 rounded-xl border ${theme === 'dark' ? 'text-emerald-400 bg-emerald-500/10 border-emerald-500/20' : 'text-emerald-500 bg-emerald-500/10 border-emerald-500/20'}`}>
                               <ShieldCheck size={20} /> تم التحقق من البريد بنجاح
                             </div>
                          )}
                          {isOtpSent && !isEmailVerified && (
                            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className={`space-y-4 p-5 rounded-2xl border border-dashed ${theme === 'dark' ? 'bg-slate-900 border-slate-700' : 'bg-blue-500/5 border-[#002D9C]/30'}`}>
                              <label className={`text-xs font-black uppercase ${theme === 'dark' ? 'text-[#38BDF8]' : 'text-[#002D9C]'}`}>أدخل الرمز المكون من ٦ أرقام</label>
                              <div className="flex gap-2">
                                <input 
                                  type="text" maxLength={6} value={otpCode}
                                  onChange={(e) => setOtpCode(e.target.value)}
                                  placeholder="000000"
                                  className={`flex-grow py-3 px-4 border-2 rounded-xl font-mono font-bold tracking-[0.4em] text-center focus:outline-none focus:ring-2 ${theme === 'dark' ? 'focus:ring-[#38BDF8] border-slate-700' : 'focus:ring-[#002D9C] border-[#002D9C]/10'} ${inputBg}`}
                                />
                                <button onClick={verifyEmailOTP} disabled={isVerifying} className={`px-6 rounded-xl font-bold text-sm transition-all ${theme === 'dark' ? 'bg-[#38BDF8] text-slate-900 hover:bg-[#60A5FA]' : 'bg-[#002D9C] text-white hover:bg-[#001D6E]'}`}>
                                  {isVerifying ? <Loader2 size={18} className="animate-spin" /> : "تحقق"}
                                </button>
                              </div>
                              {errors.otp && <p className="text-red-500 text-xs font-bold">{errors.otp}</p>}
                            </motion.div>
                          )}
                        </div>

                        <InputGroup
                          label={text.services.whatsapp}
                          placeholder="+20 1XX XXX XXXX"
                          value={formData.whatsapp}
                          error={errors.whatsapp}
                          onChange={(val) => setFormData({ ...formData, whatsapp: val })}
                          theme={theme}
                          inputBg={inputBg}
                          dir="ltr"
                        />
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <InputGroup
                          label={text.services.faculty}
                          placeholder="أدخل اسم الكلية"
                          value={formData.faculty}
                          error={errors.faculty}
                          onChange={(val) => setFormData({ ...formData, faculty: val })}
                          theme={theme}
                          inputBg={inputBg}
                        />
                        <div className="space-y-4 text-right">
                          <label className={`text-sm font-black uppercase tracking-widest ${theme === 'dark' ? 'text-[#94A3B8]' : 'text-[#001133]/60'}`}>
                            {text.services.univStatus}
                          </label>
                          <div className="flex flex-col gap-4">
                            <RadioOption id="status1" label={text.services.status1} checked={formData.applicantStatus === text.services.status1} onChange={() => setFormData({...formData, applicantStatus: text.services.status1})} theme={theme} />
                            <RadioOption id="status2" label={text.services.status2} checked={formData.applicantStatus === text.services.status2} onChange={() => setFormData({...formData, applicantStatus: text.services.status2})} theme={theme} />
                            <RadioOption id="status3" label={text.services.status3} checked={formData.applicantStatus === text.services.status3} onChange={() => setFormData({...formData, applicantStatus: text.services.status3})} theme={theme} />
                          </div>
                        </div>
                      </div>

                      <div className="space-y-4 text-right">
                        <label className={`text-sm font-black uppercase tracking-widest ${theme === 'dark' ? 'text-[#94A3B8]' : 'text-[#001133]/60'}`}>المقررات الاختيارية (اختر ٢)</label>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          {['الفصول الافتراضية', 'البحث عبر الانترنت', 'الحوسبة السحابية الشبكات', 'تطبيقات المحمول'].map((course) => (
                            <div 
                              key={course}
                              onClick={() => toggleOptionalCourse(course)}
                              className={`p-5 rounded-2xl border-2 cursor-pointer transition-all flex items-center justify-between font-bold text-sm ${
                                formData.optionalCourses.includes(course)
                                  ? (theme === 'dark' ? 'border-[#38BDF8] bg-[#38BDF8]/10 text-[#38BDF8]' : 'border-[#002D9C] bg-[#002D9C]/10 text-[#002D9C]')
                                  : (theme === 'dark' ? 'bg-slate-900 border-slate-700 text-slate-500' : 'bg-[#F0F9FF] border-[#002D9C]/10 text-[#001133]/40')
                              }`}
                            >
                              {course}
                              {formData.optionalCourses.includes(course) ? <CheckCircle2 size={20} /> : <div className={`w-5 h-5 border-2 rounded-full border-current opacity-20`} />}
                            </div>
                          ))}
                        </div>
                      </div>

                      <div className="space-y-4 text-right">
                        <label className={`text-sm font-black uppercase tracking-widest ${theme === 'dark' ? 'text-[#94A3B8]' : 'text-[#001133]/60'}`}>
                          {text.services.regType}
                        </label>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                          <SelectCard id="reg1" label={text.services.reg1} checked={formData.registrationType === text.services.reg1} onChange={() => setFormData({...formData, registrationType: text.services.reg1})} theme={theme} />
                          <SelectCard id="reg2" label={text.services.reg2} checked={formData.registrationType === text.services.reg2} onChange={() => setFormData({...formData, registrationType: text.services.reg2})} theme={theme} />
                          <SelectCard id="reg3" label={text.services.reg3} checked={formData.registrationType === text.services.reg3} onChange={() => setFormData({...formData, registrationType: text.services.reg3})} theme={theme} />
                        </div>
                      </div>

                      <div className="pt-10 flex justify-end">
                        <button
                          onClick={handleNext}
                          className={`flex items-center gap-4 px-12 py-5 ${theme === 'dark' ? 'bg-[#38BDF8] text-slate-900 hover:bg-[#60A5FA]' : 'bg-[#002D9C] text-white hover:bg-[#001D6E]'} rounded-2xl font-bold text-lg transition-all shadow-xl group ${!isEmailVerified ? 'opacity-50 cursor-not-allowed grayscale' : 'hover:-translate-y-1 active:scale-95'}`}
                        >
                          المتابعة <ArrowLeft className="group-hover:translate-x-1 transition-transform" />
                        </button>
                      </div>
                    </div>
                  </motion.div>
                ) : (
                  <motion.div
                    key="step2"
                    initial={{ opacity: 0, scale: 0.98 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 1.02 }}
                    className="space-y-8 no-print"
                  >
                    {!isEmailVerified && (
                      <div className="p-6 bg-red-500/10 border border-red-500/20 rounded-2xl flex items-center gap-4 text-red-600 font-bold">
                        <AlertCircle /> تحذير: يجب التحقق من البريد الإلكتروني لإتمام الطباعة والتحميل.
                      </div>
                    )}

                    <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
                      <button
                        onClick={handleBackToStep1}
                        className={`flex items-center gap-3 px-8 py-4 rounded-2xl font-bold transition-all border ${
                          theme === 'dark' ? 'bg-[#1E293B] border-slate-700 text-[#E5E7EB] hover:bg-slate-700' : 'bg-white border-[#002D9C]/20 text-[#002D9C] hover:bg-[#F0F9FF]'
                        }`}
                      >
                        <Edit3 size={20} /> تعديل البيانات
                      </button>
                      <div className="flex gap-4">
                        <button 
                          onClick={() => isEmailVerified && window.print()} 
                          disabled={!isEmailVerified}
                          className={`flex items-center gap-3 px-8 py-4 ${theme === 'dark' ? 'bg-slate-900 border-slate-700 text-white hover:bg-black' : 'bg-[#001133] text-white hover:bg-black'} rounded-2xl font-bold transition-all shadow-lg active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed`}
                        >
                          <Printer size={20} /> طباعة الاستمارة
                        </button>
                        <button 
                          onClick={() => isEmailVerified && window.print()} 
                          disabled={!isEmailVerified}
                          className={`flex items-center gap-3 px-8 py-4 ${theme === 'dark' ? 'bg-[#38BDF8] text-slate-900 hover:bg-[#60A5FA]' : 'bg-[#002D9C] text-white hover:bg-[#001D6E]'} rounded-2xl font-bold transition-all shadow-lg active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed`}
                        >
                          <Download size={20} /> تحميل PDF
                        </button>
                      </div>
                    </div>

                    <div className="overflow-x-auto pb-10 flex justify-center">
                       <div className={`${theme === 'dark' ? 'bg-slate-900' : 'bg-slate-500'} p-4 md:p-10 min-w-[850px] shadow-inner rounded-xl`}>
                          <OfficialFayoumForm data={formData} date={todayDate} />
                       </div>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>

              <div className="hidden print:block print-form-container">
                 <OfficialFayoumForm data={formData} date={todayDate} />
              </div>
            </div>
          )}
        </AnimatePresence>
      </div>

      <style>{`
        @media print {
          @page { size: A4 portrait; margin: 0 !important; }
          html, body { 
            margin: 0 !important; 
            padding: 0 !important; 
            background: white !important;
            height: 297mm !important;
            width: 210mm !important;
          }
          .no-print, header, footer, canvas { display: none !important; }

          #root, main, .relative.pt-32 { 
            padding: 0 !important; 
            margin: 0 !important; 
            display: block !important;
          }

          .print-form-container { 
            display: flex !important;
            justify-content: center !important;
            width: 100% !important;
            height: 100% !important;
            margin: 0 !important;
            padding: 0 !important;
            page-break-inside: avoid !important;
            page-break-after: avoid !important;
          }

          .A4-page {
            width: 210mm !important;
            height: 297mm !important;
            padding: 10mm !important;
            margin: 0 auto !important;
            border: none !important;
            box-shadow: none !important;
            box-sizing: border-box !important;
            page-break-inside: avoid !important;
            overflow: hidden !important;
          }

          * { -webkit-print-color-adjust: exact !important; color-adjust: exact !important; }
        }
      `}</style>
    </div>
  );
};

const OfficialFayoumForm: React.FC<{ data: RegistrationData, date: string }> = ({ data, date }) => (
