    <input
      type={type} dir={dir} value={value}
      onChange={(e) => onChange(e.target.value)}
      placeholder={placeholder} disabled={disabled}
      className={`w-full border-2 rounded-2xl py-4 px-5 transition-all font-medium focus:ring-2 focus:outline-none ${
        theme === 'dark' ? 'focus:ring-[#38BDF8] border-slate-700' : 'focus:ring-[#002D9C] border-[#002D9C]/10'
