  const subTextColor = theme === 'dark' ? 'text-[#94A3B8]' : 'text-[#001133]/60';

  return (
    <motion.div whileHover={{ y: -8, boxShadow: '0 25px 50px -12px rgba(0,0,0,0.4)' }} className={`p-10 rounded-[40px] border flex flex-col items-center text-center transition-all ${cardBg}`}>
