        {icon}
      </div>
      <h3 className={`text-2xl font-black mb-4 ${titleColor}`}>{title}</h3>
      <p className={`text-sm mb-10 font-medium leading-relaxed ${subTextColor}`}>{description}</p>
      <button onClick={onClick} className={`mt-auto w-full py-5 rounded-2xl font-bold transition-all shadow-xl active:scale-95 ${accentColor}`}>
        {buttonText}
      </button>
    </motion.div>
  );
